INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('0e029a78-f0ad-43cb-9b17-cca942b469b1', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Quelle est la différence avec ChatGPT ou Claude ?', '{"question":"Quelle est la différence avec ChatGPT ou Claude ?","answer":"ChatGPT et Claude vous donnent UNE réponse. Brainstorming simule un atelier collectif où 9 personnalités spécialisées dialoguent — vous voyez émerger les idées, les frictions productives, les angles non-évidents. Le livrable n''est pas une réponse, c''est une réflexion enrichie par un collectif."}', 'Quelle est la différence avec ChatGPT ou Claude ?
Quelle est la différence avec ChatGPT ou Claude ?
ChatGPT et Claude vous donnent UNE réponse. Brainstorming simule un atelier collectif où 9 personnalités spécialisées dialoguent — vous voyez émerger les idées, les frictions productives, les angles non-évidents. Le livrable n''est pas une réponse, c''est une réflexion enrichie par un collectif.', 'validated', 'import', 'apps:brainstorming', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('0e029a78-f0ad-43cb-9b17-cca942b469b1', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Quelle est la différence avec ChatGPT ou Claude ?', 'Quelle est la différence avec ChatGPT ou Claude ?
Quelle est la différence avec ChatGPT ou Claude ?
ChatGPT et Claude vous donnent UNE réponse. Brainstorming simule un atelier collectif où 9 personnalités spécialisées dialoguent — vous voyez émerger les idées, les frictions productives, les angles non-évidents. Le livrable n''est pas une réponse, c''est une réflexion enrichie par un collectif.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('664816f4-4690-46d8-b9be-a4f4a96cb9fb', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Combien de temps dure une session ?', '{"question":"Combien de temps dure une session ?","answer":"8 à 15 minutes selon la profondeur souhaitée. Vous pouvez interrompre à tout moment et solliciter directement le Synthesizer pour conclure."}', 'Combien de temps dure une session ?
