INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('9cf4ceb9-2335-4b70-b9ec-74d06e705f6e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Mes sessions sont-elles sauvegardées ?', '{"question":"Mes sessions sont-elles sauvegardées ?","answer":"Oui, les 20 dernières sessions restent en bibliothèque locale dans la sidebar Sessions. Vous pouvez les rouvrir, archiver, ou exporter la synthèse en PDF."}', 'Mes sessions sont-elles sauvegardées ?
Mes sessions sont-elles sauvegardées ?
Oui, les 20 dernières sessions restent en bibliothèque locale dans la sidebar Sessions. Vous pouvez les rouvrir, archiver, ou exporter la synthèse en PDF.', 'validated', 'import', 'apps:brainstorming', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('9cf4ceb9-2335-4b70-b9ec-74d06e705f6e', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Mes sessions sont-elles sauvegardées ?', 'Mes sessions sont-elles sauvegardées ?
