INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('29a3d443-4dc4-4b9c-ab6e-0ea802258d05', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Faut-il une clé API IA pour utiliser Brief Prod ?', '{"question":"Faut-il une clé API IA pour utiliser Brief Prod ?","answer":"Non. Le brief technique est généré mécaniquement à partir de vos saisies et téléchargeable instantanément en PDF, sans la moindre clé. L''IA n''est qu''un bonus optionnel pour ajouter 5 punchlines marketing + 3 angles de direction artistique + alertes d''incohérence en page 2 du PDF. Si vous configurez une clé Claude, GPT, Gemini, Mistral ou xAI dans le Vault, vous pouvez l''activer; sinon le plan B « copier le Code Maître + coller dans une AI web gratuite » est toujours disponible."}', 'Faut-il une clé API IA pour utiliser Brief Prod ?
Faut-il une clé API IA pour utiliser Brief Prod ?
Non. Le brief technique est généré mécaniquement à partir de vos saisies et téléchargeable instantanément en PDF, sans la moindre clé. L''IA n''est qu''un bonus optionnel pour ajouter 5 punchlines marketing + 3 angles de direction artistique + alertes d''incohérence en page 2 du PDF. Si vous configurez une clé Claude, GPT, Gemini, Mistral ou xAI dans le Vault, vous pouvez l''activer; sinon le plan B « copier le Code Maître + coller dans une AI web gratuite » est toujours disponible.', 'validated', 'import', 'apps:brief-prod', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('29a3d443-4dc4-4b9c-ab6e-0ea802258d05', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Faut-il une clé API IA pour utiliser Brief Prod ?', 'Faut-il une clé API IA pour utiliser Brief Prod ?
Faut-il une clé API IA pour utiliser Brief Prod ?
Non. Le brief technique est généré mécaniquement à partir de vos saisies et téléchargeable instantanément en PDF, sans la moindre clé. L''IA n''est qu''un bonus optionnel pour ajouter 5 punchlines marketing + 3 angles de direction artistique + alertes d''incohérence en page 2 du PDF. Si vous configurez une clé Claude, GPT, Gemini, Mistral ou xAI dans le Vault, vous pouvez l''activer; sinon le plan B « copier le Code Maître + coller dans une AI web gratuite » est toujours disponible.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('8180de57-88e4-4410-a81b-54a6db1bce87', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Que faire si mon imprimeur n''est pas Exaprint, Vistaprint ou Pixartprinting ?', '{"question":"Que faire si mon imprimeur n''est pas Exaprint, Vistaprint ou Pixartprinting ?","answer":"Choisissez « Autre imprimeur » dans le sélecteur vendor à l''étape 1: Brief Prod applique des standards génériques cohérents (bleed 3-5 mm, CMJN FOGRA39, 300 DPI) et débloque deux champs supplémentaires: URL de la fiche technique officielle + PDF de specs à joindre directement au brief. Votre graphiste suivra ces specs comme référence absolue plutôt que celles d''un vendor par défaut."}', 'Que faire si mon imprimeur n''est pas Exaprint, Vistaprint ou Pixartprinting ?
Que faire si mon imprimeur n''est pas Exaprint, Vistaprint ou Pixartprinting ?
Choisissez « Autre imprimeur » dans le sélecteur vendor à l''étape 1: Brief Prod applique des standards génériques cohérents (bleed 3-5 mm, CMJN FOGRA39, 300 DPI) et débloque deux champs supplémentaires: URL de la fiche technique officielle + PDF de specs à joindre directement au brief. Votre graphiste suivra ces specs comme référence absolue plutôt que celles d''un vendor par défaut.', 'validated', 'import', 'apps:brief-prod', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('8180de57-88e4-4410-a81b-54a6db1bce87', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Que faire si mon imprimeur n''est pas Exaprint, Vistaprint ou Pixartprinting ?', 'Que faire si mon imprimeur n''est pas Exaprint, Vistaprint ou Pixartprinting ?
Que faire si mon imprimeur n''est pas Exaprint, Vistaprint ou Pixartprinting ?
Choisissez « Autre imprimeur » dans le sélecteur vendor à l''étape 1: Brief Prod applique des standards génériques cohérents (bleed 3-5 mm, CMJN FOGRA39, 300 DPI) et débloque deux champs supplémentaires: URL de la fiche technique officielle + PDF de specs à joindre directement au brief. Votre graphiste suivra ces specs comme référence absolue plutôt que celles d''un vendor par défaut.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('b24278e0-4df3-4b52-ad09-bf11998b3653', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Quelle taille maximum pour mes uploads d''assets ?', '{"question":"Quelle taille maximum pour mes uploads d''assets ?","answer":"10 Mo par fichier (encodage inclus, soit environ 7 Mo de binaire réel). Formats acceptés: PNG, JPG, SVG, PDF, AI, EPS, GIF, WebP. Si votre fichier dépasse la limite, utilisez plutôt un lien externe WeTransfer ou Google Drive dans le champ « Brand book complet » des assets."}', 'Quelle taille maximum pour mes uploads d''assets ?
Quelle taille maximum pour mes uploads d''assets ?
10 Mo par fichier (encodage inclus, soit environ 7 Mo de binaire réel). Formats acceptés: PNG, JPG, SVG, PDF, AI, EPS, GIF, WebP. Si votre fichier dépasse la limite, utilisez plutôt un lien externe WeTransfer ou Google Drive dans le champ « Brand book complet » des assets.', 'validated', 'import', 'apps:brief-prod', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('b24278e0-4df3-4b52-ad09-bf11998b3653', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Quelle taille maximum pour mes uploads d''assets ?', 'Quelle taille maximum pour mes uploads d''assets ?
Quelle taille maximum pour mes uploads d''assets ?
10 Mo par fichier (encodage inclus, soit environ 7 Mo de binaire réel). Formats acceptés: PNG, JPG, SVG, PDF, AI, EPS, GIF, WebP. Si votre fichier dépasse la limite, utilisez plutôt un lien externe WeTransfer ou Google Drive dans le champ « Brand book complet » des assets.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('96b9b00c-876c-4120-b62f-df1d2ceff220', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Comment fonctionne le calculateur d''échelle pour les grands formats ?', '{"question":"Comment fonctionne le calculateur d''échelle pour les grands formats ?","answer":"Sur un panneau 4×3 m ou une bâche, travailler à l''échelle 1:1 produit des fichiers à 5 Go intraitables. Brief Prod calcule automatiquement le facteur de réduction (typiquement 1/10) et le DPI de sortie nécessaire en fonction de la distance de vue (autoroute = 50 m, métro = 2 m). Vous obtenez le format de travail exact (mm) + le nombre de pixels finaux + la hauteur minimum lisible des titres + une alerte si un visuel uploadé est sous-résolu pour ce contexte."}', 'Comment fonctionne le calculateur d''échelle pour les grands formats ?
Comment fonctionne le calculateur d''échelle pour les grands formats ?
Sur un panneau 4×3 m ou une bâche, travailler à l''échelle 1:1 produit des fichiers à 5 Go intraitables. Brief Prod calcule automatiquement le facteur de réduction (typiquement 1/10) et le DPI de sortie nécessaire en fonction de la distance de vue (autoroute = 50 m, métro = 2 m). Vous obtenez le format de travail exact (mm) + le nombre de pixels finaux + la hauteur minimum lisible des titres + une alerte si un visuel uploadé est sous-résolu pour ce contexte.', 'validated', 'import', 'apps:brief-prod', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('96b9b00c-876c-4120-b62f-df1d2ceff220', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Comment fonctionne le calculateur d''échelle pour les grands formats ?', 'Comment fonctionne le calculateur d''échelle pour les grands formats ?
Comment fonctionne le calculateur d''échelle pour les grands formats ?
Sur un panneau 4×3 m ou une bâche, travailler à l''échelle 1:1 produit des fichiers à 5 Go intraitables. Brief Prod calcule automatiquement le facteur de réduction (typiquement 1/10) et le DPI de sortie nécessaire en fonction de la distance de vue (autoroute = 50 m, métro = 2 m). Vous obtenez le format de travail exact (mm) + le nombre de pixels finaux + la hauteur minimum lisible des titres + une alerte si un visuel uploadé est sous-résolu pour ce contexte.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('fe2f460c-3406-446b-83f4-83796b44e018', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Mon brief n''a pas la qualité attendue, que faire ?', '{"question":"Mon brief n''a pas la qualité attendue, que faire ?","answer":"Trois leviers: 1) basculez sur un autre moteur IA via le menu « Switch engine » dans la card d''enrichissement — chaque modèle a son style propre, et l''argumentaire peut mieux passer chez Claude que chez GPT (ou inversement); 2) enrichissez votre argumentaire à l''étape 2 (plus la promesse est précise, meilleure est la sortie); 3) utilisez le « Plan B humain » en bas de l''étape 4: copiez le Code Maître et collez-le dans une AI web gratuite (Claude.ai, ChatGPT, etc.) pour comparer plusieurs réponses."}', 'Mon brief n''a pas la qualité attendue, que faire ?
Mon brief n''a pas la qualité attendue, que faire ?
Trois leviers: 1) basculez sur un autre moteur IA via le menu « Switch engine » dans la card d''enrichissement — chaque modèle a son style propre, et l''argumentaire peut mieux passer chez Claude que chez GPT (ou inversement); 2) enrichissez votre argumentaire à l''étape 2 (plus la promesse est précise, meilleure est la sortie); 3) utilisez le « Plan B humain » en bas de l''étape 4: copiez le Code Maître et collez-le dans une AI web gratuite (Claude.ai, ChatGPT, etc.) pour comparer plusieurs réponses.', 'validated', 'import', 'apps:brief-prod', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('fe2f460c-3406-446b-83f4-83796b44e018', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Mon brief n''a pas la qualité attendue, que faire ?', 'Mon brief n''a pas la qualité attendue, que faire ?
Mon brief n''a pas la qualité attendue, que faire ?
