INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('af652a4b-f79c-4360-8479-bea856de9276', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Quels imprimeurs et plateformes sont supportés ?', '{"question":"Quels imprimeurs et plateformes sont supportés ?","answer":"4 vendors × 31 supports = 42 specs précises. Imprimeurs: Exaprint (référence print FR), Vistaprint, Pixartprinting, ou « Autre imprimeur » (saisie libre). Catégories couvertes: print papier (cartes, flyers, dépliants, brochures), grand format (bâches, panneaux, roll-up), digital (réseaux sociaux), presse / édition (encarts magazine)."}', 'Quels imprimeurs et plateformes sont supportés ?
Quels imprimeurs et plateformes sont supportés ?
