INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('3dcd50a5-a707-48a2-9ef8-8d31a8feacad', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Mes visuels sont-ils stockés en sécurité ?', '{"question":"Mes visuels sont-ils stockés en sécurité ?","answer":"Oui: ils sont stockés dans une base hébergée en Europe, accessibles uniquement par vous via authentification sécurisée. Chaque asset a une URL souveraine (un lien sécurisé) qui apparaît dans le PDF du brief — votre graphiste peut télécharger directement les bons fichiers sans manipulations parallèles."}', 'Mes visuels sont-ils stockés en sécurité ?
Mes visuels sont-ils stockés en sécurité ?
