INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('3dcd50a5-a707-48a2-9ef8-8d31a8feacad', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Mes visuels sont-ils stockés en sécurité ?', 'Mes visuels sont-ils stockés en sécurité ?
