INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('1593ba27-9572-423e-8607-7578731e2ac7', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Le PDF généré est-il prêt à imprimer directement ?', '{"question":"Le PDF généré est-il prêt à imprimer directement ?","answer":"Pas l''impression elle-même: c''est un BRIEF technique. Vous le donnez à votre graphiste qui produit le visuel final selon les spécifications, ou à l''imprimeur pour validation des contraintes."}', 'Le PDF généré est-il prêt à imprimer directement ?
Le PDF généré est-il prêt à imprimer directement ?
Pas l''impression elle-même: c''est un BRIEF technique. Vous le donnez à votre graphiste qui produit le visuel final selon les spécifications, ou à l''imprimeur pour validation des contraintes.', 'validated', 'import', 'apps:brief-prod', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('1593ba27-9572-423e-8607-7578731e2ac7', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Le PDF généré est-il prêt à imprimer directement ?', 'Le PDF généré est-il prêt à imprimer directement ?
