INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('c72f3615-2922-45aa-ab98-15be6425fe5e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Brief Prod — Le brief qui sécurise', '{"statement":"Un bon brief réunit en un seul document le format, le fond perdu, le mode colorimétrique, la résolution et le type de papier attendus. L''imprimeur sait exactement quoi vérifier, vous évitez les allers-retours. Brief Prod génère ce document de cadrage pour que votre fichier parte juste du premier coup."}', 'Brief Prod — Le brief qui sécurise
Un bon brief réunit en un seul document le format, le fond perdu, le mode colorimétrique, la résolution et le type de papier attendus. L''imprimeur sait exactement quoi vérifier, vous évitez les allers-retours. Brief Prod génère ce document de cadrage pour que votre fichier parte juste du premier coup.', 'validated', 'import', 'apps:brief-prod', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('c72f3615-2922-45aa-ab98-15be6425fe5e', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Brief Prod — Le brief qui sécurise', 'Brief Prod — Le brief qui sécurise
