INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('3ad2eaad-bc9b-49ad-a9c1-f2b16f5c6ce7', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Mon texte ou mon PDF sont-ils envoyés sur Internet ?', '{"question":"Mon texte ou mon PDF sont-ils envoyés sur Internet ?","answer":"Non. La détection des fautes tourne à 100 % dans votre navigateur (moteur Grammalecte, hors-ligne). Votre PDF ne quitte jamais votre machine. Seule la « Passe IA approfondie » optionnelle envoie le texte à l''IA, et uniquement quand vous cliquez dessus."}', 'Mon texte ou mon PDF sont-ils envoyés sur Internet ?
Mon texte ou mon PDF sont-ils envoyés sur Internet ?
Non. La détection des fautes tourne à 100 % dans votre navigateur (moteur Grammalecte, hors-ligne). Votre PDF ne quitte jamais votre machine. Seule la « Passe IA approfondie » optionnelle envoie le texte à l''IA, et uniquement quand vous cliquez dessus.', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('3ad2eaad-bc9b-49ad-a9c1-f2b16f5c6ce7', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Mon texte ou mon PDF sont-ils envoyés sur Internet ?', 'Mon texte ou mon PDF sont-ils envoyés sur Internet ?
Mon texte ou mon PDF sont-ils envoyés sur Internet ?
Non. La détection des fautes tourne à 100 % dans votre navigateur (moteur Grammalecte, hors-ligne). Votre PDF ne quitte jamais votre machine. Seule la « Passe IA approfondie » optionnelle envoie le texte à l''IA, et uniquement quand vous cliquez dessus.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('393bc760-8f4b-4e58-b959-88d51d17c4f8', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Quel moteur corrige l''orthographe et la grammaire ?', '{"question":"Quel moteur corrige l''orthographe et la grammaire ?","answer":"Grammalecte, un correcteur grammatical français open source (licence GPL v3), exécuté localement. Keystone l''utilise tel quel, sans le modifier. Crédit et lien vers la source sont affichés en bas du correcteur (grammalecte.net)."}', 'Quel moteur corrige l''orthographe et la grammaire ?
Quel moteur corrige l''orthographe et la grammaire ?
Grammalecte, un correcteur grammatical français open source (licence GPL v3), exécuté localement. Keystone l''utilise tel quel, sans le modifier. Crédit et lien vers la source sont affichés en bas du correcteur (grammalecte.net).', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('393bc760-8f4b-4e58-b959-88d51d17c4f8', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Quel moteur corrige l''orthographe et la grammaire ?', 'Quel moteur corrige l''orthographe et la grammaire ?
Quel moteur corrige l''orthographe et la grammaire ?
Grammalecte, un correcteur grammatical français open source (licence GPL v3), exécuté localement. Keystone l''utilise tel quel, sans le modifier. Crédit et lien vers la source sont affichés en bas du correcteur (grammalecte.net).');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('953d83a2-2a99-4adb-8e65-8041724b0ff8', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Les PDF scannés (photos) sont-ils gérés ?', '{"question":"Les PDF scannés (photos) sont-ils gérés ?","answer":"Pas encore. Le correcteur a besoin d''une couche texte (PDF « texte », sélectionnable). Une page scannée (image) est détectée et signalée comme non supportée. La reconnaissance de texte (OCR) viendra plus tard."}', 'Les PDF scannés (photos) sont-ils gérés ?
Les PDF scannés (photos) sont-ils gérés ?
Pas encore. Le correcteur a besoin d''une couche texte (PDF « texte », sélectionnable). Une page scannée (image) est détectée et signalée comme non supportée. La reconnaissance de texte (OCR) viendra plus tard.', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('953d83a2-2a99-4adb-8e65-8041724b0ff8', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Les PDF scannés (photos) sont-ils gérés ?', 'Les PDF scannés (photos) sont-ils gérés ?
Les PDF scannés (photos) sont-ils gérés ?
Pas encore. Le correcteur a besoin d''une couche texte (PDF « texte », sélectionnable). Une page scannée (image) est détectée et signalée comme non supportée. La reconnaissance de texte (OCR) viendra plus tard.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('fa2fd2e8-7b2f-431b-8de6-47cdcf6892af', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Pourquoi le correcteur est-il gratuit mais pas la passe IA ?', '{"question":"Pourquoi le correcteur est-il gratuit mais pas la passe IA ?","answer":"La détection Grammalecte est locale et gratuite, sans limite. Seule la « Passe IA approfondie » (style, reformulation) consomme votre quota Ghost Writer, car elle fait appel à un modèle IA."}', 'Pourquoi le correcteur est-il gratuit mais pas la passe IA ?
Pourquoi le correcteur est-il gratuit mais pas la passe IA ?
La détection Grammalecte est locale et gratuite, sans limite. Seule la « Passe IA approfondie » (style, reformulation) consomme votre quota Ghost Writer, car elle fait appel à un modèle IA.', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('fa2fd2e8-7b2f-431b-8de6-47cdcf6892af', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Pourquoi le correcteur est-il gratuit mais pas la passe IA ?', 'Pourquoi le correcteur est-il gratuit mais pas la passe IA ?
Pourquoi le correcteur est-il gratuit mais pas la passe IA ?
La détection Grammalecte est locale et gratuite, sans limite. Seule la « Passe IA approfondie » (style, reformulation) consomme votre quota Ghost Writer, car elle fait appel à un modèle IA.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('8641bfba-bc36-48a4-bd3f-141213920677', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Le « PDF annoté » modifie-t-il mon document d''origine ?', '{"question":"Le « PDF annoté » modifie-t-il mon document d''origine ?","answer":"Non. Il crée une copie: vos fautes sont surlignées par-dessus sans toucher la mise en page, et une page récapitulative est ajoutée à la fin. Le texte du PDF n''est jamais réécrit à votre place."}', 'Le « PDF annoté » modifie-t-il mon document d''origine ?
Le « PDF annoté » modifie-t-il mon document d''origine ?
Non. Il crée une copie: vos fautes sont surlignées par-dessus sans toucher la mise en page, et une page récapitulative est ajoutée à la fin. Le texte du PDF n''est jamais réécrit à votre place.', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('8641bfba-bc36-48a4-bd3f-141213920677', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Le « PDF annoté » modifie-t-il mon document d''origine ?', 'Le « PDF annoté » modifie-t-il mon document d''origine ?
