INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('3e4a2c99-3c4b-407d-b37f-e71fe0cdd6ee', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Le premier lancement du correcteur est un peu long, normal ?', '{"question":"Le premier lancement du correcteur est un peu long, normal ?","answer":"Oui: le dictionnaire français (~9 Mo) se charge au premier usage, puis il est gardé en cache pour les fois suivantes (y compris hors-ligne). Les analyses suivantes sont quasi instantanées."}', 'Le premier lancement du correcteur est un peu long, normal ?
Le premier lancement du correcteur est un peu long, normal ?
Oui: le dictionnaire français (~9 Mo) se charge au premier usage, puis il est gardé en cache pour les fois suivantes (y compris hors-ligne). Les analyses suivantes sont quasi instantanées.', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('3e4a2c99-3c4b-407d-b37f-e71fe0cdd6ee', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Le premier lancement du correcteur est un peu long, normal ?', 'Le premier lancement du correcteur est un peu long, normal ?
Le premier lancement du correcteur est un peu long, normal ?
Oui: le dictionnaire français (~9 Mo) se charge au premier usage, puis il est gardé en cache pour les fois suivantes (y compris hors-ligne). Les analyses suivantes sont quasi instantanées.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('eb939519-cad1-4d5d-9657-8c943741acce', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Ghost Writer — D''où vient le ton « robotique »', '{"statement":"Un modèle vise la formulation la plus probable, donc la plus moyenne. Sans cadrage, il produit du lisse: ni faux, ni faux pas, mais sans voix. Le correctif n''est pas d''écrire moins bien, c''est de donner un contexte précis — à qui vous parlez, sur quel ton, dans quel cadre."}', 'Ghost Writer — D''où vient le ton « robotique »
Un modèle vise la formulation la plus probable, donc la plus moyenne. Sans cadrage, il produit du lisse: ni faux, ni faux pas, mais sans voix. Le correctif n''est pas d''écrire moins bien, c''est de donner un contexte précis — à qui vous parlez, sur quel ton, dans quel cadre.', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('eb939519-cad1-4d5d-9657-8c943741acce', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Ghost Writer — D''où vient le ton « robotique »', 'Ghost Writer — D''où vient le ton « robotique »
Un modèle vise la formulation la plus probable, donc la plus moyenne. Sans cadrage, il produit du lisse: ni faux, ni faux pas, mais sans voix. Le correctif n''est pas d''écrire moins bien, c''est de donner un contexte précis — à qui vous parlez, sur quel ton, dans quel cadre.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('4e36b05e-8656-4cbb-8703-93dd06db2850', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Ghost Writer — Les bons réflexes', '{"statement":"Choisir le registre: un e-mail pro, une note interne et un texte marketing n''ont ni la même longueur ni la même chaleur. Calibrez avant d''écrire. Comparer des variantes: produire plusieurs versions d''un même message et garder ce qui sonne vous, plutôt que d''accepter la première sortie. Garder la main: couper les superlatifs, raccourcir, réinjecter un détail concret que seule votre activité connaît. Relire pour de vrai: l''orthographe et les accords se vérifient à part — idéalement en local, sans envoyer votre texte sur un serveur tiers. Ghost Writer suit cette logique: trois variantes calibrées selon le contexte pour trouver votre ton, et un correcteur orthographique qui travaille sur votre appareil, sans rien envoyer en ligne."}', 'Ghost Writer — Les bons réflexes
Choisir le registre: un e-mail pro, une note interne et un texte marketing n''ont ni la même longueur ni la même chaleur. Calibrez avant d''écrire. Comparer des variantes: produire plusieurs versions d''un même message et garder ce qui sonne vous, plutôt que d''accepter la première sortie. Garder la main: couper les superlatifs, raccourcir, réinjecter un détail concret que seule votre activité connaît. Relire pour de vrai: l''orthographe et les accords se vérifient à part — idéalement en local, sans envoyer votre texte sur un serveur tiers. Ghost Writer suit cette logique: trois variantes calibrées selon le contexte pour trouver votre ton, et un correcteur orthographique qui travaille sur votre appareil, sans rien envoyer en ligne.', 'validated', 'import', 'apps:ghost-writer', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('4e36b05e-8656-4cbb-8703-93dd06db2850', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Ghost Writer — Les bons réflexes', 'Ghost Writer — Les bons réflexes
Choisir le registre: un e-mail pro, une note interne et un texte marketing n''ont ni la même longueur ni la même chaleur. Calibrez avant d''écrire. Comparer des variantes: produire plusieurs versions d''un même message et garder ce qui sonne vous, plutôt que d''accepter la première sortie. Garder la main: couper les superlatifs, raccourcir, réinjecter un détail concret que seule votre activité connaît. Relire pour de vrai: l''orthographe et les accords se vérifient à part — idéalement en local, sans envoyer votre texte sur un serveur tiers. Ghost Writer suit cette logique: trois variantes calibrées selon le contexte pour trouver votre ton, et un correcteur orthographique qui travaille sur votre appareil, sans rien envoyer en ligne.');
