INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('76a01eb7-12cc-4ded-a167-92fd93e332c0', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Key Brand, en une phrase', 'Key Brand, en une phrase
