INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('7b3d36ac-e9e3-46d5-b322-64cb55e2e4e2', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'À qui s''adresse Key Brand ?', '{"question":"À qui s''adresse Key Brand ?","answer":"Aux entreprises qui veulent une charte simple et pratique (un logo, des couleurs, une police suffisent), comme aux graphistes et agences qui livrent des chartes complètes à leurs clients. La même charte s''adapte: elle ne montre que ce que vous y mettez."}', 'À qui s''adresse Key Brand ?
À qui s''adresse Key Brand ?
Aux entreprises qui veulent une charte simple et pratique (un logo, des couleurs, une police suffisent), comme aux graphistes et agences qui livrent des chartes complètes à leurs clients. La même charte s''adapte: elle ne montre que ce que vous y mettez.', 'validated', 'import', 'apps:key-brand', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('7b3d36ac-e9e3-46d5-b322-64cb55e2e4e2', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'À qui s''adresse Key Brand ?', 'À qui s''adresse Key Brand ?
À qui s''adresse Key Brand ?
Aux entreprises qui veulent une charte simple et pratique (un logo, des couleurs, une police suffisent), comme aux graphistes et agences qui livrent des chartes complètes à leurs clients. La même charte s''adapte: elle ne montre que ce que vous y mettez.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('95007035-62ee-4f09-87ee-54b96b39eb47', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Est-ce que ça remplace mon PDF de charte graphique ?', '{"question":"Est-ce que ça remplace mon PDF de charte graphique ?","answer":"C''est le but. Le PDF vieillit dès qu''il est envoyé; votre charte Key Brand reste à jour en permanence, et ceux qui la consultent copient les codes couleur et téléchargent le logo directement, sans vous redemander les fichiers. Un export PDF restera disponible pour ceux qui en exigent un."}', 'Est-ce que ça remplace mon PDF de charte graphique ?
Est-ce que ça remplace mon PDF de charte graphique ?
C''est le but. Le PDF vieillit dès qu''il est envoyé; votre charte Key Brand reste à jour en permanence, et ceux qui la consultent copient les codes couleur et téléchargent le logo directement, sans vous redemander les fichiers. Un export PDF restera disponible pour ceux qui en exigent un.', 'validated', 'import', 'apps:key-brand', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('95007035-62ee-4f09-87ee-54b96b39eb47', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Est-ce que ça remplace mon PDF de charte graphique ?', 'Est-ce que ça remplace mon PDF de charte graphique ?
Est-ce que ça remplace mon PDF de charte graphique ?
C''est le but. Le PDF vieillit dès qu''il est envoyé; votre charte Key Brand reste à jour en permanence, et ceux qui la consultent copient les codes couleur et téléchargent le logo directement, sans vous redemander les fichiers. Un export PDF restera disponible pour ceux qui en exigent un.');
