INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('ce30deb8-fdb4-48fa-9657-f09ed12e9f48', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Combien de temps les réponses sont-elles conservées ?', '{"question":"Combien de temps les réponses sont-elles conservées ?","answer":"Selon la TTL que vous avez choisie (30, 90, 180 ou 365 jours). Après expiration, suppression automatique côté serveur — conformité RGPD Art. 5 native. Le mail Resend reste dans la boîte du destinataire indéfiniment."}', 'Combien de temps les réponses sont-elles conservées ?
Combien de temps les réponses sont-elles conservées ?
Selon la TTL que vous avez choisie (30, 90, 180 ou 365 jours). Après expiration, suppression automatique côté serveur — conformité RGPD Art. 5 native. Le mail Resend reste dans la boîte du destinataire indéfiniment.', 'validated', 'import', 'apps:key-form', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('ce30deb8-fdb4-48fa-9657-f09ed12e9f48', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Combien de temps les réponses sont-elles conservées ?', 'Combien de temps les réponses sont-elles conservées ?
