INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('b1458c83-1269-489c-87e4-c817207960da', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Mes répondants doivent-ils créer un compte ?', '{"question":"Mes répondants doivent-ils créer un compte ?","answer":"Non, le formulaire est ouvert et anonyme par défaut. Vous pouvez activer un code d''accès optionnel dans l''étape Apparence pour les questionnaires confidentiels."}', 'Mes répondants doivent-ils créer un compte ?
