INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('809de42e-8dda-45e3-82ea-f02cc8abe124', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Puis-je dupliquer un formulaire existant ?', '{"question":"Puis-je dupliquer un formulaire existant ?","answer":"Oui: dans la bibliothèque, bouton ''Dupliquer''. Idéal pour réutiliser une structure (par exemple Biennale 2026 → Biennale 2027) en ne changeant que les destinataires et quelques champs."}', 'Puis-je dupliquer un formulaire existant ?
