INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('809de42e-8dda-45e3-82ea-f02cc8abe124', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Puis-je dupliquer un formulaire existant ?', 'Puis-je dupliquer un formulaire existant ?
