INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('731e8567-4940-42d0-8082-e383bf817b70', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Comment fonctionne la logique conditionnelle ?', '{"question":"Comment fonctionne la logique conditionnelle ?","answer":"Sélectionnez un champ dans le builder, puis dans l''éditeur de droite ouvrez ''Visibilité conditionnelle'' ou ''Obligatoire conditionnel''. Vous pouvez aussi configurer une somme automatique entre champs Montant."}', 'Comment fonctionne la logique conditionnelle ?
