INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('731e8567-4940-42d0-8082-e383bf817b70', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Comment fonctionne la logique conditionnelle ?', 'Comment fonctionne la logique conditionnelle ?
