INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2dfc0661-ea61-42f7-b738-272b985d1e56', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Puis-je pré-remplir des champs via l''URL ?', '{"question":"Puis-je pré-remplir des champs via l''URL ?","answer":"Oui: chaque champ a un ID technique (visible dans son éditeur) qui peut être utilisé en query param. Exemple: keystone.app/f/biennale?fld_nom=Marie+Durand."}', 'Puis-je pré-remplir des champs via l''URL ?
