INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('d3949c84-f0c3-48b5-9178-889e35da9e51', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Quels types de fichiers les répondants peuvent-ils joindre ?', '{"question":"Quels types de fichiers les répondants peuvent-ils joindre ?","answer":"Pas d''upload direct. À la place, utilisez le type ''Lien externe'': le répondant colle un lien WeTransfer, Drive, Dropbox ou Vimeo."}', 'Quels types de fichiers les répondants peuvent-ils joindre ?
