INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('d3949c84-f0c3-48b5-9178-889e35da9e51', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Quels types de fichiers les répondants peuvent-ils joindre ?', 'Quels types de fichiers les répondants peuvent-ils joindre ?
