INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('cb9d99e2-3c33-4c7d-8cf4-40090c197bcf', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Key Form — L''alternative aux formulaires classiques', '{"statement":"Construire un formulaire est aujourd''hui à la portée de tous: on choisit ses champs, on rédige ses questions, on partage un lien. Pas de code, pas d''hébergement à gérer. Le vrai sujet n''est plus technique, il est juridique."}', 'Key Form — L''alternative aux formulaires classiques
Construire un formulaire est aujourd''hui à la portée de tous: on choisit ses champs, on rédige ses questions, on partage un lien. Pas de code, pas d''hébergement à gérer. Le vrai sujet n''est plus technique, il est juridique.', 'validated', 'import', 'apps:key-form', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('cb9d99e2-3c33-4c7d-8cf4-40090c197bcf', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Key Form — L''alternative aux formulaires classiques', 'Key Form — L''alternative aux formulaires classiques
Construire un formulaire est aujourd''hui à la portée de tous: on choisit ses champs, on rédige ses questions, on partage un lien. Pas de code, pas d''hébergement à gérer. Le vrai sujet n''est plus technique, il est juridique.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('764e100d-667a-425c-af7a-53aecd1ca3ad', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Key Form — Pourquoi le RGPD compte ici', '{"statement":"Un formulaire collecte presque toujours des données personnelles — nom, e-mail, parfois plus. Beaucoup d''outils gratuits stockent ces réponses sur des serveurs hors d''Europe, les analysent, voire les monétisent. Vous restez pourtant responsable de ce que deviennent les données de vos répondants. Consentement clair: la personne sait à quoi elle s''engage en répondant. Données maîtrisées: pas de revente, pas de traceurs publicitaires greffés sur votre formulaire. Hébergement maîtrisé: savoir où les réponses sont conservées, et pouvoir les supprimer. Minimisation: ne demander que les champs réellement utiles. Moins vous collectez, moins vous portez de risque. Ces principes ne sont pas un luxe juridique: ils protègent vos répondants et vous évitent d''engager votre responsabilité sans le savoir, pour un simple formulaire de contact."}', 'Key Form — Pourquoi le RGPD compte ici
Un formulaire collecte presque toujours des données personnelles — nom, e-mail, parfois plus. Beaucoup d''outils gratuits stockent ces réponses sur des serveurs hors d''Europe, les analysent, voire les monétisent. Vous restez pourtant responsable de ce que deviennent les données de vos répondants. Consentement clair: la personne sait à quoi elle s''engage en répondant. Données maîtrisées: pas de revente, pas de traceurs publicitaires greffés sur votre formulaire. Hébergement maîtrisé: savoir où les réponses sont conservées, et pouvoir les supprimer. Minimisation: ne demander que les champs réellement utiles. Moins vous collectez, moins vous portez de risque. Ces principes ne sont pas un luxe juridique: ils protègent vos répondants et vous évitent d''engager votre responsabilité sans le savoir, pour un simple formulaire de contact.', 'validated', 'import', 'apps:key-form', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('764e100d-667a-425c-af7a-53aecd1ca3ad', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Key Form — Pourquoi le RGPD compte ici', 'Key Form — Pourquoi le RGPD compte ici
Un formulaire collecte presque toujours des données personnelles — nom, e-mail, parfois plus. Beaucoup d''outils gratuits stockent ces réponses sur des serveurs hors d''Europe, les analysent, voire les monétisent. Vous restez pourtant responsable de ce que deviennent les données de vos répondants. Consentement clair: la personne sait à quoi elle s''engage en répondant. Données maîtrisées: pas de revente, pas de traceurs publicitaires greffés sur votre formulaire. Hébergement maîtrisé: savoir où les réponses sont conservées, et pouvoir les supprimer. Minimisation: ne demander que les champs réellement utiles. Moins vous collectez, moins vous portez de risque. Ces principes ne sont pas un luxe juridique: ils protègent vos répondants et vous évitent d''engager votre responsabilité sans le savoir, pour un simple formulaire de contact.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('35da7c55-bba5-4555-8f00-fad4f5e34848', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Key Form — Partager simplement', '{"statement":"Un bon formulaire se diffuse par un simple lien ou un QR code — sur une affiche, un e-mail, un comptoir. Le répondant ouvre, remplit, valide; vous récupérez des réponses propres, sans friction. Key Form réunit ces deux exigences: la simplicité d''un formulaire sans code et la conformité RGPD par défaut, partageable par lien ou QR."}', 'Key Form — Partager simplement
Un bon formulaire se diffuse par un simple lien ou un QR code — sur une affiche, un e-mail, un comptoir. Le répondant ouvre, remplit, valide; vous récupérez des réponses propres, sans friction. Key Form réunit ces deux exigences: la simplicité d''un formulaire sans code et la conformité RGPD par défaut, partageable par lien ou QR.', 'validated', 'import', 'apps:key-form', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('35da7c55-bba5-4555-8f00-fad4f5e34848', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Key Form — Partager simplement', 'Key Form — Partager simplement
Un bon formulaire se diffuse par un simple lien ou un QR code — sur une affiche, un e-mail, un comptoir. Le répondant ouvre, remplit, valide; vous récupérez des réponses propres, sans friction. Key Form réunit ces deux exigences: la simplicité d''un formulaire sans code et la conformité RGPD par défaut, partageable par lien ou QR.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('86963628-51d3-4707-a4db-5398da9f20de', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'definition', 'Keynapse, en une phrase', '{"term":"Keynapse","definition":"Votre espace personnel de connaissances. Des bulles de notes qui respirent sur un canevas infini, regroupées en zones de couleur et reliées par des traits. Chaque bulle s''ouvre dans un panneau où vous écrivez, cochez des tâches, attachez des photos, des croquis et des mémos vocaux (que l''IA transcrit et transforme en tâches ou rappels), et posez des rappels qui vous préviennent à l''heure dite. Vos notes restent privées: rien n''est publié."}', 'Keynapse, en une phrase
Keynapse
Votre espace personnel de connaissances. Des bulles de notes qui respirent sur un canevas infini, regroupées en zones de couleur et reliées par des traits. Chaque bulle s''ouvre dans un panneau où vous écrivez, cochez des tâches, attachez des photos, des croquis et des mémos vocaux (que l''IA transcrit et transforme en tâches ou rappels), et posez des rappels qui vous préviennent à l''heure dite. Vos notes restent privées: rien n''est publié.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('86963628-51d3-4707-a4db-5398da9f20de', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse, en une phrase', 'Keynapse, en une phrase
Keynapse
Votre espace personnel de connaissances. Des bulles de notes qui respirent sur un canevas infini, regroupées en zones de couleur et reliées par des traits. Chaque bulle s''ouvre dans un panneau où vous écrivez, cochez des tâches, attachez des photos, des croquis et des mémos vocaux (que l''IA transcrit et transforme en tâches ou rappels), et posez des rappels qui vous préviennent à l''heure dite. Vos notes restent privées: rien n''est publié.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2f410f54-2a04-4fa9-91ee-0b4a625ed6a3', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse · Créer une bulle', '{"statement":"Créer une bulle: le bouton « + » crée une bulle dans la vue courante. Un clic sur une bulle ouvre son panneau (à droite sur ordinateur, en bas sur mobile). Glissez une bulle pour la déplacer, sa position est mémorisée."}', 'Keynapse · Créer une bulle
Créer une bulle: le bouton « + » crée une bulle dans la vue courante. Un clic sur une bulle ouvre son panneau (à droite sur ordinateur, en bas sur mobile). Glissez une bulle pour la déplacer, sa position est mémorisée.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('2f410f54-2a04-4fa9-91ee-0b4a625ed6a3', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse · Créer une bulle', 'Keynapse · Créer une bulle
Créer une bulle: le bouton « + » crée une bulle dans la vue courante. Un clic sur une bulle ouvre son panneau (à droite sur ordinateur, en bas sur mobile). Glissez une bulle pour la déplacer, sa position est mémorisée.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('c14de90e-715e-4f23-879f-6b5f9fe2f85a', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse · Naviguer le canevas', '{"statement":"Naviguer le canevas: molette ou pincement pour zoomer, glisser le fond pour vous déplacer. « Tout voir » recadre sur l''ensemble de vos bulles. De loin vous voyez les zones, de près le détail."}', 'Keynapse · Naviguer le canevas
Naviguer le canevas: molette ou pincement pour zoomer, glisser le fond pour vous déplacer. « Tout voir » recadre sur l''ensemble de vos bulles. De loin vous voyez les zones, de près le détail.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('c14de90e-715e-4f23-879f-6b5f9fe2f85a', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse · Naviguer le canevas', 'Keynapse · Naviguer le canevas
Naviguer le canevas: molette ou pincement pour zoomer, glisser le fond pour vous déplacer. « Tout voir » recadre sur l''ensemble de vos bulles. De loin vous voyez les zones, de près le détail.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('b96dc294-8f5f-4525-a95d-b593421fe296', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse · Ranger en zones', '{"statement":"Ranger en zones: le bouton Zones ouvre le gestionnaire (créer, renommer, recolorer, aller à une zone). Les bulles d''une même zone partagent sa couleur et se regroupent doucement. Une bulle peut rester libre."}', 'Keynapse · Ranger en zones
Ranger en zones: le bouton Zones ouvre le gestionnaire (créer, renommer, recolorer, aller à une zone). Les bulles d''une même zone partagent sa couleur et se regroupent doucement. Une bulle peut rester libre.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('b96dc294-8f5f-4525-a95d-b593421fe296', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse · Ranger en zones', 'Keynapse · Ranger en zones
Ranger en zones: le bouton Zones ouvre le gestionnaire (créer, renommer, recolorer, aller à une zone). Les bulles d''une même zone partagent sa couleur et se regroupent doucement. Une bulle peut rester libre.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('37c05180-df3e-47d0-ae4c-2196ccc90213', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse · Tisser des liens', '{"statement":"Tisser des liens: dans le panneau d''une bulle, section « Liens » → « Relier à… ». Cliquez une bulle reliée pour que la caméra y vole. Le « × » à droite d''un lien le retire."}', 'Keynapse · Tisser des liens
Tisser des liens: dans le panneau d''une bulle, section « Liens » → « Relier à… ». Cliquez une bulle reliée pour que la caméra y vole. Le « × » à droite d''un lien le retire.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('37c05180-df3e-47d0-ae4c-2196ccc90213', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse · Tisser des liens', 'Keynapse · Tisser des liens
Tisser des liens: dans le panneau d''une bulle, section « Liens » → « Relier à… ». Cliquez une bulle reliée pour que la caméra y vole. Le « × » à droite d''un lien le retire.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('e399cb2e-8568-454b-bb0f-817013128c31', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse · Captures', '{"statement":"Captures: ajoutez une photo, un croquis dessiné, ou un mémo vocal. La note vocale est transcrite et l''IA vous propose des tâches et des rappels à cocher avant de les créer. Tout est consultable en plein écran."}', 'Keynapse · Captures
Captures: ajoutez une photo, un croquis dessiné, ou un mémo vocal. La note vocale est transcrite et l''IA vous propose des tâches et des rappels à cocher avant de les créer. Tout est consultable en plein écran.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('e399cb2e-8568-454b-bb0f-817013128c31', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse · Captures', 'Keynapse · Captures
Captures: ajoutez une photo, un croquis dessiné, ou un mémo vocal. La note vocale est transcrite et l''IA vous propose des tâches et des rappels à cocher avant de les créer. Tout est consultable en plein écran.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('1b132955-9f30-4416-9680-f4dfb2582bc6', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse · Rappels', '{"statement":"Rappels: posez une date, une heure (à la molette) et une répétition. Tant que Keynapse est ouvert, un bandeau et une sonnerie vous préviennent à l''échéance; sur ordinateur, une notification système peut aussi s''afficher."}', 'Keynapse · Rappels
Rappels: posez une date, une heure (à la molette) et une répétition. Tant que Keynapse est ouvert, un bandeau et une sonnerie vous préviennent à l''échéance; sur ordinateur, une notification système peut aussi s''afficher.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('1b132955-9f30-4416-9680-f4dfb2582bc6', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse · Rappels', 'Keynapse · Rappels
Rappels: posez une date, une heure (à la molette) et une répétition. Tant que Keynapse est ouvert, un bandeau et une sonnerie vous préviennent à l''échéance; sur ordinateur, une notification système peut aussi s''afficher.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('5a411fe6-4c68-41a1-9e1e-2acd05d081f3', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Où sont stockées mes notes ? Sont-elles privées ?', '{"question":"Où sont stockées mes notes ? Sont-elles privées ?","answer":"Tout est rangé dans votre espace Keystone (base de données et stockage de fichiers), rattaché à votre compte. Vos bulles, photos, croquis et mémos vocaux ne sont jamais publics ni partagés: Keynapse est un outil personnel."}', 'Où sont stockées mes notes ? Sont-elles privées ?
Où sont stockées mes notes ? Sont-elles privées ?
Tout est rangé dans votre espace Keystone (base de données et stockage de fichiers), rattaché à votre compte. Vos bulles, photos, croquis et mémos vocaux ne sont jamais publics ni partagés: Keynapse est un outil personnel.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('5a411fe6-4c68-41a1-9e1e-2acd05d081f3', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Où sont stockées mes notes ? Sont-elles privées ?', 'Où sont stockées mes notes ? Sont-elles privées ?
Où sont stockées mes notes ? Sont-elles privées ?
Tout est rangé dans votre espace Keystone (base de données et stockage de fichiers), rattaché à votre compte. Vos bulles, photos, croquis et mémos vocaux ne sont jamais publics ni partagés: Keynapse est un outil personnel.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2f0ef248-ccfa-4f59-8953-2a634f00b34e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'La note vocale consomme-t-elle des crédits IA ?', '{"question":"La note vocale consomme-t-elle des crédits IA ?","answer":"Oui: la transcription du mémo puis l''analyse qui en tire des tâches et rappels comptent comme des actions IA (au compteur de crédits). L''enregistrement audio, lui, est toujours conservé même si l''IA n''est pas disponible — vous ne perdez jamais votre mémo."}', 'La note vocale consomme-t-elle des crédits IA ?
La note vocale consomme-t-elle des crédits IA ?
Oui: la transcription du mémo puis l''analyse qui en tire des tâches et rappels comptent comme des actions IA (au compteur de crédits). L''enregistrement audio, lui, est toujours conservé même si l''IA n''est pas disponible — vous ne perdez jamais votre mémo.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('2f0ef248-ccfa-4f59-8953-2a634f00b34e', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'La note vocale consomme-t-elle des crédits IA ?', 'La note vocale consomme-t-elle des crédits IA ?
La note vocale consomme-t-elle des crédits IA ?
Oui: la transcription du mémo puis l''analyse qui en tire des tâches et rappels comptent comme des actions IA (au compteur de crédits). L''enregistrement audio, lui, est toujours conservé même si l''IA n''est pas disponible — vous ne perdez jamais votre mémo.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('ab5ae601-d3be-43a2-88ef-4bed43ec3d27', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Serai-je prévenu d''un rappel si Keynapse est fermé ?', '{"question":"Serai-je prévenu d''un rappel si Keynapse est fermé ?","answer":"Les notifications sont locales: elles se déclenchent quand le pad est ouvert (bandeau dans l''app + sonnerie, et notification système sur ordinateur si vous l''avez autorisée). Sur iPhone dans Safari, seul le bandeau s''affiche. Les rappels par notification même app fermée viendront plus tard."}', 'Serai-je prévenu d''un rappel si Keynapse est fermé ?
Serai-je prévenu d''un rappel si Keynapse est fermé ?
Les notifications sont locales: elles se déclenchent quand le pad est ouvert (bandeau dans l''app + sonnerie, et notification système sur ordinateur si vous l''avez autorisée). Sur iPhone dans Safari, seul le bandeau s''affiche. Les rappels par notification même app fermée viendront plus tard.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('ab5ae601-d3be-43a2-88ef-4bed43ec3d27', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Serai-je prévenu d''un rappel si Keynapse est fermé ?', 'Serai-je prévenu d''un rappel si Keynapse est fermé ?
Serai-je prévenu d''un rappel si Keynapse est fermé ?
Les notifications sont locales: elles se déclenchent quand le pad est ouvert (bandeau dans l''app + sonnerie, et notification système sur ordinateur si vous l''avez autorisée). Sur iPhone dans Safari, seul le bandeau s''affiche. Les rappels par notification même app fermée viendront plus tard.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('3169f49b-b720-4e38-aa32-49c72216c977', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Comment supprimer un lien, une capture ou un rappel ?', '{"question":"Comment supprimer un lien, une capture ou un rappel ?","answer":"Ouvrez la bulle concernée: chaque lien, chaque vignette de capture et chaque rappel a un « × » pour le retirer. Pour supprimer une bulle entière, utilisez « Supprimer cette bulle » en bas de son panneau (avec confirmation)."}', 'Comment supprimer un lien, une capture ou un rappel ?
Comment supprimer un lien, une capture ou un rappel ?
Ouvrez la bulle concernée: chaque lien, chaque vignette de capture et chaque rappel a un « × » pour le retirer. Pour supprimer une bulle entière, utilisez « Supprimer cette bulle » en bas de son panneau (avec confirmation).', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('3169f49b-b720-4e38-aa32-49c72216c977', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Comment supprimer un lien, une capture ou un rappel ?', 'Comment supprimer un lien, une capture ou un rappel ?
Comment supprimer un lien, une capture ou un rappel ?
Ouvrez la bulle concernée: chaque lien, chaque vignette de capture et chaque rappel a un « × » pour le retirer. Pour supprimer une bulle entière, utilisez « Supprimer cette bulle » en bas de son panneau (avec confirmation).');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('9183da23-1e54-46d5-bc4f-438ef41fb2a9', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'L''animation des bulles me gêne (mal de mer).', '{"question":"L''animation des bulles me gêne (mal de mer).","answer":"Le bouton en forme d''onde, en haut à droite, fige la respiration des bulles et la souplesse des liens: la carte se stabilise, tout reste cliquable et déplaçable. Votre choix est mémorisé, et Keynapse respecte aussi le réglage « réduire les animations » de votre appareil."}', 'L''animation des bulles me gêne (mal de mer).
L''animation des bulles me gêne (mal de mer).
Le bouton en forme d''onde, en haut à droite, fige la respiration des bulles et la souplesse des liens: la carte se stabilise, tout reste cliquable et déplaçable. Votre choix est mémorisé, et Keynapse respecte aussi le réglage « réduire les animations » de votre appareil.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('9183da23-1e54-46d5-bc4f-438ef41fb2a9', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'L''animation des bulles me gêne (mal de mer).', 'L''animation des bulles me gêne (mal de mer).
L''animation des bulles me gêne (mal de mer).
Le bouton en forme d''onde, en haut à droite, fige la respiration des bulles et la souplesse des liens: la carte se stabilise, tout reste cliquable et déplaçable. Votre choix est mémorisé, et Keynapse respecte aussi le réglage « réduire les animations » de votre appareil.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('087cd122-eede-4715-8438-4dd792bc0144', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse — La limite des notes linéaires', '{"statement":"Dans une liste, deux idées proches mais notées à dix jours d''écart se retrouvent loin l''une de l''autre. On perd les rapprochements. On ne voit pas non plus la « forme » de l''ensemble: quels sujets prennent de l''ampleur, lesquels restent isolés. L''information est là, mais pas la vue d''ensemble."}', 'Keynapse — La limite des notes linéaires
Dans une liste, deux idées proches mais notées à dix jours d''écart se retrouvent loin l''une de l''autre. On perd les rapprochements. On ne voit pas non plus la « forme » de l''ensemble: quels sujets prennent de l''ampleur, lesquels restent isolés. L''information est là, mais pas la vue d''ensemble.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('087cd122-eede-4715-8438-4dd792bc0144', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse — La limite des notes linéaires', 'Keynapse — La limite des notes linéaires
Dans une liste, deux idées proches mais notées à dix jours d''écart se retrouvent loin l''une de l''autre. On perd les rapprochements. On ne voit pas non plus la « forme » de l''ensemble: quels sujets prennent de l''ampleur, lesquels restent isolés. L''information est là, mais pas la vue d''ensemble.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('7b5f1ad1-2bef-4477-a634-264cf1f9e09f', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse — Ce qu''apporte un espace visuel', '{"statement":"Le spatial: poser chaque idée à un endroit, la déplacer, la rapprocher d''une autre. La mémoire retient mieux ce qui a une position. Les regroupements: rassembler par zones de couleur ce qui va ensemble, sans imposer de hiérarchie rigide. Les liens: relier deux idées éloignées d''un trait, et naviguer de l''une à l''autre — c''est là que naissent les connexions inattendues. Le zoom: voir les grands ensembles de loin, le détail de près, comme une carte."}', 'Keynapse — Ce qu''apporte un espace visuel
Le spatial: poser chaque idée à un endroit, la déplacer, la rapprocher d''une autre. La mémoire retient mieux ce qui a une position. Les regroupements: rassembler par zones de couleur ce qui va ensemble, sans imposer de hiérarchie rigide. Les liens: relier deux idées éloignées d''un trait, et naviguer de l''une à l''autre — c''est là que naissent les connexions inattendues. Le zoom: voir les grands ensembles de loin, le détail de près, comme une carte.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('7b5f1ad1-2bef-4477-a634-264cf1f9e09f', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse — Ce qu''apporte un espace visuel', 'Keynapse — Ce qu''apporte un espace visuel
Le spatial: poser chaque idée à un endroit, la déplacer, la rapprocher d''une autre. La mémoire retient mieux ce qui a une position. Les regroupements: rassembler par zones de couleur ce qui va ensemble, sans imposer de hiérarchie rigide. Les liens: relier deux idées éloignées d''un trait, et naviguer de l''une à l''autre — c''est là que naissent les connexions inattendues. Le zoom: voir les grands ensembles de loin, le détail de près, comme une carte.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('bd1b299f-a10e-4eff-bdc8-ce71e60018aa', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Keynapse — Linéaire ou visuel: pas l''un contre l''autre', '{"statement":"Une liste reste idéale pour une tâche à cocher ou un compte rendu. Le visuel prend le dessus dès qu''il s''agit d''explorer, de structurer un projet flou, de faire émerger un plan. Les deux se complètent. Keynapse est cet espace visuel: des bulles de notes sur un canevas infini, regroupées en zones et reliées entre elles, qui restent entièrement privées."}', 'Keynapse — Linéaire ou visuel: pas l''un contre l''autre
Une liste reste idéale pour une tâche à cocher ou un compte rendu. Le visuel prend le dessus dès qu''il s''agit d''explorer, de structurer un projet flou, de faire émerger un plan. Les deux se complètent. Keynapse est cet espace visuel: des bulles de notes sur un canevas infini, regroupées en zones et reliées entre elles, qui restent entièrement privées.', 'validated', 'import', 'apps:keynapse', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('bd1b299f-a10e-4eff-bdc8-ce71e60018aa', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Keynapse — Linéaire ou visuel: pas l''un contre l''autre', 'Keynapse — Linéaire ou visuel: pas l''un contre l''autre
Une liste reste idéale pour une tâche à cocher ou un compte rendu. Le visuel prend le dessus dès qu''il s''agit d''explorer, de structurer un projet flou, de faire émerger un plan. Les deux se complètent. Keynapse est cet espace visuel: des bulles de notes sur un canevas infini, regroupées en zones et reliées entre elles, qui restent entièrement privées.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('c53b8f3b-8775-4179-af5b-6e1fd9702cdb', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'definition', 'Missive, en une phrase', '{"term":"Missive","definition":"Missive transmet un secret — mot de passe, code, information sensible — qui se lit une seule fois puis s''autodétruit. Le contenu est chiffré sur votre appareil: même nous ne pouvons pas le lire. Vous partagez un lien (ou un QR, ou une puce NFC) et, par un autre canal, un code de déverrouillage. Au-delà de quelques essais ratés, la missive meurt définitivement."}', 'Missive, en une phrase
Missive
Missive transmet un secret — mot de passe, code, information sensible — qui se lit une seule fois puis s''autodétruit. Le contenu est chiffré sur votre appareil: même nous ne pouvons pas le lire. Vous partagez un lien (ou un QR, ou une puce NFC) et, par un autre canal, un code de déverrouillage. Au-delà de quelques essais ratés, la missive meurt définitivement.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('c53b8f3b-8775-4179-af5b-6e1fd9702cdb', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive, en une phrase', 'Missive, en une phrase
Missive
Missive transmet un secret — mot de passe, code, information sensible — qui se lit une seule fois puis s''autodétruit. Le contenu est chiffré sur votre appareil: même nous ne pouvons pas le lire. Vous partagez un lien (ou un QR, ou une puce NFC) et, par un autre canal, un code de déverrouillage. Au-delà de quelques essais ratés, la missive meurt définitivement.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('8b85e67b-50d8-4414-b463-7d4dfb43550b', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive · Créer une missive', '{"statement":"Créer une missive: collez le secret, choisissez le nombre d''essais et l''expiration, puis « Sceller ». Tout est chiffré sur votre appareil — le serveur ne voit jamais le contenu en clair."}', 'Missive · Créer une missive
Créer une missive: collez le secret, choisissez le nombre d''essais et l''expiration, puis « Sceller ». Tout est chiffré sur votre appareil — le serveur ne voit jamais le contenu en clair.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('8b85e67b-50d8-4414-b463-7d4dfb43550b', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive · Créer une missive', 'Missive · Créer une missive
Créer une missive: collez le secret, choisissez le nombre d''essais et l''expiration, puis « Sceller ». Tout est chiffré sur votre appareil — le serveur ne voit jamais le contenu en clair.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('910a789d-5ae9-40f0-93e0-15d8fb59e71a', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive · Deux éléments à transmettre, par deux ca', '{"statement":"Deux éléments à transmettre, par deux canaux différents: le lien (ou le QR / la puce NFC) d''un côté, et le code de déverrouillage de l''autre. Deux formats de code au choix: « Sécurité maximale » (long, à copier-coller) ou « Facile à dicter » (3 mots + un nombre, parfait au téléphone). Le code n''est affiché qu''une fois et n''est pas récupérable — notez-le ou copiez-le avant de fermer."}', 'Missive · Deux éléments à transmettre, par deux ca
Deux éléments à transmettre, par deux canaux différents: le lien (ou le QR / la puce NFC) d''un côté, et le code de déverrouillage de l''autre. Deux formats de code au choix: « Sécurité maximale » (long, à copier-coller) ou « Facile à dicter » (3 mots + un nombre, parfait au téléphone). Le code n''est affiché qu''une fois et n''est pas récupérable — notez-le ou copiez-le avant de fermer.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('910a789d-5ae9-40f0-93e0-15d8fb59e71a', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive · Deux éléments à transmettre, par deux ca', 'Missive · Deux éléments à transmettre, par deux ca
Deux éléments à transmettre, par deux canaux différents: le lien (ou le QR / la puce NFC) d''un côté, et le code de déverrouillage de l''autre. Deux formats de code au choix: « Sécurité maximale » (long, à copier-coller) ou « Facile à dicter » (3 mots + un nombre, parfait au téléphone). Le code n''est affiché qu''une fois et n''est pas récupérable — notez-le ou copiez-le avant de fermer.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('558b5bac-cf0f-496f-a7bc-9d14f3ed69ae', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive · Lecture unique', '{"statement":"Lecture unique: le destinataire ouvre le lien, saisit le code, lit le message — puis la missive se referme. Vous êtes averti quand elle a été ouverte (dans la barre d''ambiance du tableau de bord)."}', 'Missive · Lecture unique
Lecture unique: le destinataire ouvre le lien, saisit le code, lit le message — puis la missive se referme. Vous êtes averti quand elle a été ouverte (dans la barre d''ambiance du tableau de bord).', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('558b5bac-cf0f-496f-a7bc-9d14f3ed69ae', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive · Lecture unique', 'Missive · Lecture unique
Lecture unique: le destinataire ouvre le lien, saisit le code, lit le message — puis la missive se referme. Vous êtes averti quand elle a été ouverte (dans la barre d''ambiance du tableau de bord).');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('be17818a-81a5-40fe-980c-cb11727da8a8', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive · Autodestruction', '{"statement":"Autodestruction: après le nombre d''essais choisi (3 par défaut, ou 1 pour un usage strict), la missive meurt — plus personne ne peut l''ouvrir, même avec le bon code. Si une missive meurt sur des essais ratés sans avoir été lue, une alerte « possible interception » s''affiche."}', 'Missive · Autodestruction
Autodestruction: après le nombre d''essais choisi (3 par défaut, ou 1 pour un usage strict), la missive meurt — plus personne ne peut l''ouvrir, même avec le bon code. Si une missive meurt sur des essais ratés sans avoir été lue, une alerte « possible interception » s''affiche.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('be17818a-81a5-40fe-980c-cb11727da8a8', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive · Autodestruction', 'Missive · Autodestruction
Autodestruction: après le nombre d''essais choisi (3 par défaut, ou 1 pour un usage strict), la missive meurt — plus personne ne peut l''ouvrir, même avec le bon code. Si une missive meurt sur des essais ratés sans avoir été lue, une alerte « possible interception » s''affiche.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('c33a8baf-b555-4de6-b901-6f2fee9a80e4', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive · Jetons réutilisables', '{"statement":"Jetons réutilisables: créez un objet physique (puce NFC ou QR) que vous écrivez une seule fois, puis rechargez avec un nouveau secret autant de fois que vous voulez — sans jamais retoucher l''objet."}', 'Missive · Jetons réutilisables
Jetons réutilisables: créez un objet physique (puce NFC ou QR) que vous écrivez une seule fois, puis rechargez avec un nouveau secret autant de fois que vous voulez — sans jamais retoucher l''objet.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('c33a8baf-b555-4de6-b901-6f2fee9a80e4', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive · Jetons réutilisables', 'Missive · Jetons réutilisables
Jetons réutilisables: créez un objet physique (puce NFC ou QR) que vous écrivez une seule fois, puis rechargez avec un nouveau secret autant de fois que vous voulez — sans jamais retoucher l''objet.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('ac722643-8c73-46b1-8b31-901453bc71d5', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive · NFC', '{"statement":"NFC: l''écriture d''une puce demande un téléphone Android avec Chrome. Sur iPhone et ordinateur, utilisez le QR ou le lien (toujours proposés). La lecture au contact fonctionne sur iPhone récent comme sur Android."}', 'Missive · NFC
NFC: l''écriture d''une puce demande un téléphone Android avec Chrome. Sur iPhone et ordinateur, utilisez le QR ou le lien (toujours proposés). La lecture au contact fonctionne sur iPhone récent comme sur Android.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('ac722643-8c73-46b1-8b31-901453bc71d5', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive · NFC', 'Missive · NFC
NFC: l''écriture d''une puce demande un téléphone Android avec Chrome. Sur iPhone et ordinateur, utilisez le QR ou le lien (toujours proposés). La lecture au contact fonctionne sur iPhone récent comme sur Android.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('28867128-01cd-43fc-a56a-ae8169e11230', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Est-ce vraiment sécurisé ? Pouvez-vous lire mes secrets ?', '{"question":"Est-ce vraiment sécurisé ? Pouvez-vous lire mes secrets ?","answer":"Non, nous ne pouvons pas les lire. Le secret est chiffré de bout en bout sur votre appareil avec une clé dérivée du code de déverrouillage, que nous ne voyons jamais. Nos serveurs ne stockent que du contenu chiffré, illisible sans le code. La seule limite honnête: cette page web est servie par notre serveur, donc une sécurité de niveau « secret d''État » supposerait de ne pas nous faire confiance pour le code de la page — pour tout usage courant (mots de passe, codes, infos sensibles), c''est solide."}', 'Est-ce vraiment sécurisé ? Pouvez-vous lire mes secrets ?
Est-ce vraiment sécurisé ? Pouvez-vous lire mes secrets ?
Non, nous ne pouvons pas les lire. Le secret est chiffré de bout en bout sur votre appareil avec une clé dérivée du code de déverrouillage, que nous ne voyons jamais. Nos serveurs ne stockent que du contenu chiffré, illisible sans le code. La seule limite honnête: cette page web est servie par notre serveur, donc une sécurité de niveau « secret d''État » supposerait de ne pas nous faire confiance pour le code de la page — pour tout usage courant (mots de passe, codes, infos sensibles), c''est solide.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('28867128-01cd-43fc-a56a-ae8169e11230', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Est-ce vraiment sécurisé ? Pouvez-vous lire mes secrets ?', 'Est-ce vraiment sécurisé ? Pouvez-vous lire mes secrets ?
Est-ce vraiment sécurisé ? Pouvez-vous lire mes secrets ?
Non, nous ne pouvons pas les lire. Le secret est chiffré de bout en bout sur votre appareil avec une clé dérivée du code de déverrouillage, que nous ne voyons jamais. Nos serveurs ne stockent que du contenu chiffré, illisible sans le code. La seule limite honnête: cette page web est servie par notre serveur, donc une sécurité de niveau « secret d''État » supposerait de ne pas nous faire confiance pour le code de la page — pour tout usage courant (mots de passe, codes, infos sensibles), c''est solide.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('271fe03f-b907-40e4-b1c0-aaf7dcf9fcd7', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Que se passe-t-il si je perds le code de déverrouillage ?', '{"question":"Que se passe-t-il si je perds le code de déverrouillage ?","answer":"Le secret est définitivement perdu. C''est le prix de la confidentialité réelle: personne, pas même nous, ne peut le récupérer. Transmettez le code au destinataire dès la création, par un canal différent du lien."}', 'Que se passe-t-il si je perds le code de déverrouillage ?
Que se passe-t-il si je perds le code de déverrouillage ?
Le secret est définitivement perdu. C''est le prix de la confidentialité réelle: personne, pas même nous, ne peut le récupérer. Transmettez le code au destinataire dès la création, par un canal différent du lien.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('271fe03f-b907-40e4-b1c0-aaf7dcf9fcd7', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Que se passe-t-il si je perds le code de déverrouillage ?', 'Que se passe-t-il si je perds le code de déverrouillage ?
Que se passe-t-il si je perds le code de déverrouillage ?
Le secret est définitivement perdu. C''est le prix de la confidentialité réelle: personne, pas même nous, ne peut le récupérer. Transmettez le code au destinataire dès la création, par un canal différent du lien.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('6fed7e36-a3a9-4808-9d2d-e49c753bcce2', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Par quel canal transmettre le code ?', '{"question":"Par quel canal transmettre le code ?","answer":"Par un canal différent de celui du lien, et de préférence pas par SMS seul (vulnérable au détournement de carte SIM). De vive voix, par un autre messager, ou en personne: l''idée est qu''une seule interception ne donne jamais à la fois le lien et le code."}', 'Par quel canal transmettre le code ?
Par quel canal transmettre le code ?
Par un canal différent de celui du lien, et de préférence pas par SMS seul (vulnérable au détournement de carte SIM). De vive voix, par un autre messager, ou en personne: l''idée est qu''une seule interception ne donne jamais à la fois le lien et le code.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('6fed7e36-a3a9-4808-9d2d-e49c753bcce2', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Par quel canal transmettre le code ?', 'Par quel canal transmettre le code ?
Par quel canal transmettre le code ?
Par un canal différent de celui du lien, et de préférence pas par SMS seul (vulnérable au détournement de carte SIM). De vive voix, par un autre messager, ou en personne: l''idée est qu''une seule interception ne donne jamais à la fois le lien et le code.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('d4358eff-f995-490a-82a6-dfed3ad90870', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Que peut-on envoyer par Missive — et qu''est-ce qu''il vaut mieux éviter ?', '{"question":"Que peut-on envoyer par Missive — et qu''est-ce qu''il vaut mieux éviter ?","answer":"Missive est faite pour les secrets opérationnels: mots de passe, codes d''accès, coordonnées bancaires à saisir, clés API, instructions confidentielles ponctuelles. À l''inverse, évitez d''y faire passer SEUL tout ce qui pourrait devoir être prouvé plus tard: engagement contractuel, échange RH sensible, instruction qui engage votre responsabilité. Une missive détruite ne peut pas servir de preuve — c''est voulu. Pour ces sujets, doublez par un canal archivé (email). Règle simple à adopter en équipe: « Missive = transmettre un secret, jamais archiver une décision. Tout ce qui a valeur de preuve passe aussi par l''email. »"}', 'Que peut-on envoyer par Missive — et qu''est-ce qu''il vaut mieux éviter ?
Que peut-on envoyer par Missive — et qu''est-ce qu''il vaut mieux éviter ?
Missive est faite pour les secrets opérationnels: mots de passe, codes d''accès, coordonnées bancaires à saisir, clés API, instructions confidentielles ponctuelles. À l''inverse, évitez d''y faire passer SEUL tout ce qui pourrait devoir être prouvé plus tard: engagement contractuel, échange RH sensible, instruction qui engage votre responsabilité. Une missive détruite ne peut pas servir de preuve — c''est voulu. Pour ces sujets, doublez par un canal archivé (email). Règle simple à adopter en équipe: « Missive = transmettre un secret, jamais archiver une décision. Tout ce qui a valeur de preuve passe aussi par l''email. »', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('d4358eff-f995-490a-82a6-dfed3ad90870', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Que peut-on envoyer par Missive — et qu''est-ce qu''il vaut mieux éviter ?', 'Que peut-on envoyer par Missive — et qu''est-ce qu''il vaut mieux éviter ?
Que peut-on envoyer par Missive — et qu''est-ce qu''il vaut mieux éviter ?
Missive est faite pour les secrets opérationnels: mots de passe, codes d''accès, coordonnées bancaires à saisir, clés API, instructions confidentielles ponctuelles. À l''inverse, évitez d''y faire passer SEUL tout ce qui pourrait devoir être prouvé plus tard: engagement contractuel, échange RH sensible, instruction qui engage votre responsabilité. Une missive détruite ne peut pas servir de preuve — c''est voulu. Pour ces sujets, doublez par un canal archivé (email). Règle simple à adopter en équipe: « Missive = transmettre un secret, jamais archiver une décision. Tout ce qui a valeur de preuve passe aussi par l''email. »');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('f19a4a7a-1d08-4da8-a8b7-28cfd44512d9', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Missive est-elle compatible RGPD ? Que noter dans mon registre des traitements ?', '{"question":"Missive est-elle compatible RGPD ? Que noter dans mon registre des traitements ?","answer":"Oui — et plutôt deux fois qu''une: la minimisation et la limitation de conservation que le RGPD recommande sont ici garanties par construction (contenu chiffré illisible par l''éditeur, autodestruction, traces techniques purgées sous 24 h). Si vous tenez un registre des traitements, vous pouvez y recopier ceci: « Transmission ponctuelle d''informations sensibles via messagerie éphémère chiffrée de bout en bout (Missive, Keystone OS). Contenu illisible par l''éditeur; autodestruction après lecture unique, expiration ou épuisement des essais; métadonnées techniques purgées sous 24 heures. Ce canal n''est pas utilisé pour des données soumises à une obligation légale de conservation. » Une donnée déjà autodétruite ne peut plus être fournie lors d''une demande d''accès: c''est conforme, du moment que c''est documenté et que le canal n''est pas utilisé pour ce qui doit être conservé."}', 'Missive est-elle compatible RGPD ? Que noter dans mon registre des traitements ?
Missive est-elle compatible RGPD ? Que noter dans mon registre des traitements ?
Oui — et plutôt deux fois qu''une: la minimisation et la limitation de conservation que le RGPD recommande sont ici garanties par construction (contenu chiffré illisible par l''éditeur, autodestruction, traces techniques purgées sous 24 h). Si vous tenez un registre des traitements, vous pouvez y recopier ceci: « Transmission ponctuelle d''informations sensibles via messagerie éphémère chiffrée de bout en bout (Missive, Keystone OS). Contenu illisible par l''éditeur; autodestruction après lecture unique, expiration ou épuisement des essais; métadonnées techniques purgées sous 24 heures. Ce canal n''est pas utilisé pour des données soumises à une obligation légale de conservation. » Une donnée déjà autodétruite ne peut plus être fournie lors d''une demande d''accès: c''est conforme, du moment que c''est documenté et que le canal n''est pas utilisé pour ce qui doit être conservé.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('f19a4a7a-1d08-4da8-a8b7-28cfd44512d9', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive est-elle compatible RGPD ? Que noter dans mon registre des traitements ?', 'Missive est-elle compatible RGPD ? Que noter dans mon registre des traitements ?
Missive est-elle compatible RGPD ? Que noter dans mon registre des traitements ?
Oui — et plutôt deux fois qu''une: la minimisation et la limitation de conservation que le RGPD recommande sont ici garanties par construction (contenu chiffré illisible par l''éditeur, autodestruction, traces techniques purgées sous 24 h). Si vous tenez un registre des traitements, vous pouvez y recopier ceci: « Transmission ponctuelle d''informations sensibles via messagerie éphémère chiffrée de bout en bout (Missive, Keystone OS). Contenu illisible par l''éditeur; autodestruction après lecture unique, expiration ou épuisement des essais; métadonnées techniques purgées sous 24 heures. Ce canal n''est pas utilisé pour des données soumises à une obligation légale de conservation. » Une donnée déjà autodétruite ne peut plus être fournie lors d''une demande d''accès: c''est conforme, du moment que c''est documenté et que le canal n''est pas utilisé pour ce qui doit être conservé.');
