INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('e0a7e602-0805-48fa-a591-2b41175f2462', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive — Les bons réflexes', '{"statement":"Chiffrement de bout en bout: le secret est illisible, y compris pour le service qui le transmet. Lecture unique: le message s''autodétruit après avoir été lu une fois. Deux canaux séparés: le lien d''un côté, le code de déverrouillage de l''autre (de vive voix, autre messagerie). Une seule interception ne suffit alors jamais. Une expiration: si le destinataire ne lit pas à temps, le secret meurt."}', 'Missive — Les bons réflexes
Chiffrement de bout en bout: le secret est illisible, y compris pour le service qui le transmet. Lecture unique: le message s''autodétruit après avoir été lu une fois. Deux canaux séparés: le lien d''un côté, le code de déverrouillage de l''autre (de vive voix, autre messagerie). Une seule interception ne suffit alors jamais. Une expiration: si le destinataire ne lit pas à temps, le secret meurt.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('e0a7e602-0805-48fa-a591-2b41175f2462', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive — Les bons réflexes', 'Missive — Les bons réflexes
Chiffrement de bout en bout: le secret est illisible, y compris pour le service qui le transmet. Lecture unique: le message s''autodétruit après avoir été lu une fois. Deux canaux séparés: le lien d''un côté, le code de déverrouillage de l''autre (de vive voix, autre messagerie). Une seule interception ne suffit alors jamais. Une expiration: si le destinataire ne lit pas à temps, le secret meurt.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('31e5c097-aafa-4167-aba0-7fa23bb51e5d', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive — Ce que « sécurisé » veut dire (et ne veut pas dire)', '{"statement":"Un bon outil garantit qu''on ne peut plus accéder au message après lecture, et qu''il était illisible en transit. Il ne protège pas contre un destinataire qui photographie son propre écran: c''est de l''éphémère sécurisé, pas de l''anti-capture. Pour un mot de passe, un code ou une information sensible, c''est largement suffisant. Missive applique exactement ces principes: chiffré sur votre appareil, lu une seule fois, lien et code par deux canaux, expiration et autodestruction."}', 'Missive — Ce que « sécurisé » veut dire (et ne veut pas dire)
Un bon outil garantit qu''on ne peut plus accéder au message après lecture, et qu''il était illisible en transit. Il ne protège pas contre un destinataire qui photographie son propre écran: c''est de l''éphémère sécurisé, pas de l''anti-capture. Pour un mot de passe, un code ou une information sensible, c''est largement suffisant. Missive applique exactement ces principes: chiffré sur votre appareil, lu une seule fois, lien et code par deux canaux, expiration et autodestruction.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('31e5c097-aafa-4167-aba0-7fa23bb51e5d', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive — Ce que « sécurisé » veut dire (et ne veut pas dire)', 'Missive — Ce que « sécurisé » veut dire (et ne veut pas dire)
Un bon outil garantit qu''on ne peut plus accéder au message après lecture, et qu''il était illisible en transit. Il ne protège pas contre un destinataire qui photographie son propre écran: c''est de l''éphémère sécurisé, pas de l''anti-capture. Pour un mot de passe, un code ou une information sensible, c''est largement suffisant. Missive applique exactement ces principes: chiffré sur votre appareil, lu une seule fois, lien et code par deux canaux, expiration et autodestruction.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('cf3db162-6171-462e-94ad-0eefa3a75d66', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Missive — Encadrer l''usage en entreprise', '{"statement":"Un message autodétruit ne peut pas servir de preuve — c''est sa raison d''être. La bonne pratique en équipe tient en une règle: Missive sert à transmettre un secret, jamais à archiver une décision. Engagements, échanges RH, instructions qui engagent la responsabilité: doublez-les par un canal archivé (email). Côté RGPD, l''éphémère chiffré joue pour vous — minimisation et conservation limitée sont garanties par construction — à condition de documenter ce choix dans votre registre des traitements et de réserver le canal aux données sans obligation légale de conservation."}', 'Missive — Encadrer l''usage en entreprise
Un message autodétruit ne peut pas servir de preuve — c''est sa raison d''être. La bonne pratique en équipe tient en une règle: Missive sert à transmettre un secret, jamais à archiver une décision. Engagements, échanges RH, instructions qui engagent la responsabilité: doublez-les par un canal archivé (email). Côté RGPD, l''éphémère chiffré joue pour vous — minimisation et conservation limitée sont garanties par construction — à condition de documenter ce choix dans votre registre des traitements et de réserver le canal aux données sans obligation légale de conservation.', 'validated', 'import', 'apps:missive', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('cf3db162-6171-462e-94ad-0eefa3a75d66', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Missive — Encadrer l''usage en entreprise', 'Missive — Encadrer l''usage en entreprise
Un message autodétruit ne peut pas servir de preuve — c''est sa raison d''être. La bonne pratique en équipe tient en une règle: Missive sert à transmettre un secret, jamais à archiver une décision. Engagements, échanges RH, instructions qui engagent la responsabilité: doublez-les par un canal archivé (email). Côté RGPD, l''éphémère chiffré joue pour vous — minimisation et conservation limitée sont garanties par construction — à condition de documenter ce choix dans votre registre des traitements et de réserver le canal aux données sans obligation légale de conservation.');
