INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('68bda4b7-a0bc-435c-8708-7bdfda10f918', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Qu''est-ce qui consomme des crédits IA, et qu''est-ce qui est gratuit ?', '{"question":"Qu''est-ce qui consomme des crédits IA, et qu''est-ce qui est gratuit ?","answer":"La surveillance, l''audit complet et les correctifs « code à coller » sont gratuits (aucune IA). Seuls « Rédiger avec l''IA » (méta description, FAQ) et la mesure de visibilité IA (GEO) consomment des crédits — environ 1 par génération ou par mesure. Avec votre propre clé moteur (votre propre clé), ces actions passent hors compteur."}', 'Qu''est-ce qui consomme des crédits IA, et qu''est-ce qui est gratuit ?
Qu''est-ce qui consomme des crédits IA, et qu''est-ce qui est gratuit ?
La surveillance, l''audit complet et les correctifs « code à coller » sont gratuits (aucune IA). Seuls « Rédiger avec l''IA » (méta description, FAQ) et la mesure de visibilité IA (GEO) consomment des crédits — environ 1 par génération ou par mesure. Avec votre propre clé moteur (votre propre clé), ces actions passent hors compteur.', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('68bda4b7-a0bc-435c-8708-7bdfda10f918', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Qu''est-ce qui consomme des crédits IA, et qu''est-ce qui est gratuit ?', 'Qu''est-ce qui consomme des crédits IA, et qu''est-ce qui est gratuit ?
Qu''est-ce qui consomme des crédits IA, et qu''est-ce qui est gratuit ?
La surveillance, l''audit complet et les correctifs « code à coller » sont gratuits (aucune IA). Seuls « Rédiger avec l''IA » (méta description, FAQ) et la mesure de visibilité IA (GEO) consomment des crédits — environ 1 par génération ou par mesure. Avec votre propre clé moteur (votre propre clé), ces actions passent hors compteur.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('e44ff807-783b-4caa-a782-a5c6f2576db7', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Pourquoi l''axe « Visibilité IA (GEO) » n''apparaît-il pas ?', '{"question":"Pourquoi l''axe « Visibilité IA (GEO) » n''apparaît-il pas ?","answer":"Le GEO s''active dès qu''une clé moteur est configurée côté serveur (une clé Gemini gratuite suffit pour démarrer). Tant qu''aucune clé n''est posée, l''axe et le bouton « Mesurer » restent masqués — le reste de l''audit fonctionne normalement."}', 'Pourquoi l''axe « Visibilité IA (GEO) » n''apparaît-il pas ?
Pourquoi l''axe « Visibilité IA (GEO) » n''apparaît-il pas ?
Le GEO s''active dès qu''une clé moteur est configurée côté serveur (une clé Gemini gratuite suffit pour démarrer). Tant qu''aucune clé n''est posée, l''axe et le bouton « Mesurer » restent masqués — le reste de l''audit fonctionne normalement.', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('e44ff807-783b-4caa-a782-a5c6f2576db7', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Pourquoi l''axe « Visibilité IA (GEO) » n''apparaît-il pas ?', 'Pourquoi l''axe « Visibilité IA (GEO) » n''apparaît-il pas ?
Pourquoi l''axe « Visibilité IA (GEO) » n''apparaît-il pas ?
Le GEO s''active dès qu''une clé moteur est configurée côté serveur (une clé Gemini gratuite suffit pour démarrer). Tant qu''aucune clé n''est posée, l''axe et le bouton « Mesurer » restent masqués — le reste de l''audit fonctionne normalement.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('e5d7fa24-ccfa-4885-92f7-a79d073036b5', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Sentinel fonctionne-t-il avec Wix, WordPress et un site sur-mesure ?', '{"question":"Sentinel fonctionne-t-il avec Wix, WordPress et un site sur-mesure ?","answer":"Oui. Sentinel détecte la plateforme à partir du site et adapte les instructions de chaque correctif: où cliquer dans votre éditeur, ou bien le bloc de code exact à coller dans l''en-tête. C''est pensé pour un utilisateur non technique."}', 'Sentinel fonctionne-t-il avec Wix, WordPress et un site sur-mesure ?
Sentinel fonctionne-t-il avec Wix, WordPress et un site sur-mesure ?
Oui. Sentinel détecte la plateforme à partir du site et adapte les instructions de chaque correctif: où cliquer dans votre éditeur, ou bien le bloc de code exact à coller dans l''en-tête. C''est pensé pour un utilisateur non technique.', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('e5d7fa24-ccfa-4885-92f7-a79d073036b5', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Sentinel fonctionne-t-il avec Wix, WordPress et un site sur-mesure ?', 'Sentinel fonctionne-t-il avec Wix, WordPress et un site sur-mesure ?
Sentinel fonctionne-t-il avec Wix, WordPress et un site sur-mesure ?
Oui. Sentinel détecte la plateforme à partir du site et adapte les instructions de chaque correctif: où cliquer dans votre éditeur, ou bien le bloc de code exact à coller dans l''en-tête. C''est pensé pour un utilisateur non technique.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('b7137981-7507-4514-9fe6-a17f4db3ad35', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Pourquoi je ne vois pas le nombre de jours avant l''expiration du certificat SSL ?', '{"question":"Pourquoi je ne vois pas le nombre de jours avant l''expiration du certificat SSL ?","answer":"Un site en HTTPS qui répond a un certificat valide à l''instant de la vérification. Le compte à rebours précis (J-14) n''est pas lisible de manière souveraine par notre sonde; il sera ajouté via une vérification dédiée. En attendant, une chute du HTTPS est détectée par la veille."}', 'Pourquoi je ne vois pas le nombre de jours avant l''expiration du certificat SSL ?
Pourquoi je ne vois pas le nombre de jours avant l''expiration du certificat SSL ?
Un site en HTTPS qui répond a un certificat valide à l''instant de la vérification. Le compte à rebours précis (J-14) n''est pas lisible de manière souveraine par notre sonde; il sera ajouté via une vérification dédiée. En attendant, une chute du HTTPS est détectée par la veille.', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('b7137981-7507-4514-9fe6-a17f4db3ad35', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Pourquoi je ne vois pas le nombre de jours avant l''expiration du certificat SSL ?', 'Pourquoi je ne vois pas le nombre de jours avant l''expiration du certificat SSL ?
Pourquoi je ne vois pas le nombre de jours avant l''expiration du certificat SSL ?
Un site en HTTPS qui répond a un certificat valide à l''instant de la vérification. Le compte à rebours précis (J-14) n''est pas lisible de manière souveraine par notre sonde; il sera ajouté via une vérification dédiée. En attendant, une chute du HTTPS est détectée par la veille.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('8273ba79-4c78-457f-a582-ee54e950747b', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Que reçoit mon webmaster par e-mail ?', '{"question":"Que reçoit mon webmaster par e-mail ?","answer":"Le rapport complet: le score, les problèmes classés par priorité, les étapes adaptées à la plateforme et le code prêt à coller. L''envoi e-mail s''active côté serveur; tant qu''il ne l''est pas, le bouton reste masqué et l''export PDF prend le relais."}', 'Que reçoit mon webmaster par e-mail ?
Que reçoit mon webmaster par e-mail ?
Le rapport complet: le score, les problèmes classés par priorité, les étapes adaptées à la plateforme et le code prêt à coller. L''envoi e-mail s''active côté serveur; tant qu''il ne l''est pas, le bouton reste masqué et l''export PDF prend le relais.', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('8273ba79-4c78-457f-a582-ee54e950747b', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Que reçoit mon webmaster par e-mail ?', 'Que reçoit mon webmaster par e-mail ?
Que reçoit mon webmaster par e-mail ?
Le rapport complet: le score, les problèmes classés par priorité, les étapes adaptées à la plateforme et le code prêt à coller. L''envoi e-mail s''active côté serveur; tant qu''il ne l''est pas, le bouton reste masqué et l''export PDF prend le relais.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2474c045-b2d3-43dc-bd2d-2004e903fa27', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Sentinel — Comment une IA choisit qui citer', '{"statement":"Une identité claire et cohérente: même nom, adresse et téléphone partout (site, annuaires, fiche Google), reliés à votre fiche légale officielle. Des données structurées (schema.org) qui disent qui vous êtes et ce que vous faites. Des sources tierces qui parlent de vous — avis, annuaires, presse: les IA s''y fient plus qu''à votre propre site. Du contenu qui répond aux vraies questions de vos clients, pas seulement des pages de vente. Des avis récents et une présence locale soignée."}', 'Sentinel — Comment une IA choisit qui citer
Une identité claire et cohérente: même nom, adresse et téléphone partout (site, annuaires, fiche Google), reliés à votre fiche légale officielle. Des données structurées (schema.org) qui disent qui vous êtes et ce que vous faites. Des sources tierces qui parlent de vous — avis, annuaires, presse: les IA s''y fient plus qu''à votre propre site. Du contenu qui répond aux vraies questions de vos clients, pas seulement des pages de vente. Des avis récents et une présence locale soignée.', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('2474c045-b2d3-43dc-bd2d-2004e903fa27', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Sentinel — Comment une IA choisit qui citer', 'Sentinel — Comment une IA choisit qui citer
Une identité claire et cohérente: même nom, adresse et téléphone partout (site, annuaires, fiche Google), reliés à votre fiche légale officielle. Des données structurées (schema.org) qui disent qui vous êtes et ce que vous faites. Des sources tierces qui parlent de vous — avis, annuaires, presse: les IA s''y fient plus qu''à votre propre site. Du contenu qui répond aux vraies questions de vos clients, pas seulement des pages de vente. Des avis récents et une présence locale soignée.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('bf52a9c4-6f80-4d5a-b366-de6f3075165c', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Sentinel — Par où commencer', '{"statement":"Assurez-vous que le nom de votre entreprise renvoie sans ambiguïté à une seule entité, publiez vos mentions légales et votre politique de confidentialité, créez votre fiche d''établissement, et récoltez des avis authentiques. Puis écrivez quelques pages qui répondent aux questions que vos clients posent réellement."}', 'Sentinel — Par où commencer
Assurez-vous que le nom de votre entreprise renvoie sans ambiguïté à une seule entité, publiez vos mentions légales et votre politique de confidentialité, créez votre fiche d''établissement, et récoltez des avis authentiques. Puis écrivez quelques pages qui répondent aux questions que vos clients posent réellement.', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('bf52a9c4-6f80-4d5a-b366-de6f3075165c', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Sentinel — Par où commencer', 'Sentinel — Par où commencer
Assurez-vous que le nom de votre entreprise renvoie sans ambiguïté à une seule entité, publiez vos mentions légales et votre politique de confidentialité, créez votre fiche d''établissement, et récoltez des avis authentiques. Puis écrivez quelques pages qui répondent aux questions que vos clients posent réellement.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('d27f57ac-e684-4edc-bf62-8fc73026edee', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Sentinel — Comment savoir si ça marche', '{"statement":"La seule façon de le savoir, c''est de mesurer: poser la question à plusieurs IA et regarder si vous êtes cité, et sur quelles requêtes. C''est exactement ce que fait Sentinel — il suit votre visibilité dans les IA dans le temps, en plus de l''audit web classique (disponibilité, SEO, sécurité, accessibilité)."}', 'Sentinel — Comment savoir si ça marche
La seule façon de le savoir, c''est de mesurer: poser la question à plusieurs IA et regarder si vous êtes cité, et sur quelles requêtes. C''est exactement ce que fait Sentinel — il suit votre visibilité dans les IA dans le temps, en plus de l''audit web classique (disponibilité, SEO, sécurité, accessibilité).', 'validated', 'import', 'apps:sentinel', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('d27f57ac-e684-4edc-bf62-8fc73026edee', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Sentinel — Comment savoir si ça marche', 'Sentinel — Comment savoir si ça marche
La seule façon de le savoir, c''est de mesurer: poser la question à plusieurs IA et regarder si vous êtes cité, et sur quelles requêtes. C''est exactement ce que fait Sentinel — il suit votre visibilité dans les IA dans le temps, en plus de l''audit web classique (disponibilité, SEO, sécurité, accessibilité).');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('f5b99287-ad06-446e-a397-4f232820bbe9', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'definition', 'Smart Agent, en une phrase', '{"term":"Smart Agent","definition":"Votre jumeau numérique de savoir-faire. Un agent qui répond à vos clients UNIQUEMENT depuis le savoir que vous avez validé — jamais d''invention: s''il ne sait pas, il le dit, et la question rejoint sa liste de travail. Vous le nourrissez (texte, page web, fichier, interview guidée), vous le testez, puis vous le publiez par lien ou QR code: vos visiteurs lui parlent sans compte, à l''écrit ou à la voix."}', 'Smart Agent, en une phrase
Smart Agent
Votre jumeau numérique de savoir-faire. Un agent qui répond à vos clients UNIQUEMENT depuis le savoir que vous avez validé — jamais d''invention: s''il ne sait pas, il le dit, et la question rejoint sa liste de travail. Vous le nourrissez (texte, page web, fichier, interview guidée), vous le testez, puis vous le publiez par lien ou QR code: vos visiteurs lui parlent sans compte, à l''écrit ou à la voix.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('f5b99287-ad06-446e-a397-4f232820bbe9', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent, en une phrase', 'Smart Agent, en une phrase
