Votre jumeau numérique de savoir-faire. Un agent qui répond à vos clients UNIQUEMENT depuis le savoir que vous avez validé — jamais d''invention: s''il ne sait pas, il le dit, et la question rejoint sa liste de travail. Vous le nourrissez (texte, page web, fichier, interview guidée), vous le testez, puis vous le publiez par lien ou QR code: vos visiteurs lui parlent sans compte, à l''écrit ou à la voix.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('34ec11d8-6290-4c83-83d2-8ae131415532', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent · Créer l''agent', '{"statement":"Créer l''agent: « Nouvel agent » → partez d''un gabarit métier (vendeur, agent immobilier, gardien de musée, concierge, guide, SAV…) qui pré-remplit son rôle, son style et son objectif. Tout reste modifiable dans Réglages."}', 'Smart Agent · Créer l''agent
Créer l''agent: « Nouvel agent » → partez d''un gabarit métier (vendeur, agent immobilier, gardien de musée, concierge, guide, SAV…) qui pré-remplit son rôle, son style et son objectif. Tout reste modifiable dans Réglages.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('34ec11d8-6290-4c83-83d2-8ae131415532', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent · Créer l''agent', 'Smart Agent · Créer l''agent
