INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('7c5fbbca-846a-4974-83f6-f74e8c14eb5b', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent · Le nourrir', '{"statement":"Le nourrir: onglet Savoir → « Démarrer avec un pack métier » installe des fiches de savoir-faire prêtes à relire, et « Répondre aux questions du métier » lance l''interview guidée: vous répondez à l''oral ou au clavier, l''IA structure en fiches. « Nourrir le coffre » accepte aussi un texte collé, une page de votre site ou un fichier (PDF, Word, Excel…)."}', 'Smart Agent · Le nourrir
Le nourrir: onglet Savoir → « Démarrer avec un pack métier » installe des fiches de savoir-faire prêtes à relire, et « Répondre aux questions du métier » lance l''interview guidée: vous répondez à l''oral ou au clavier, l''IA structure en fiches. « Nourrir le coffre » accepte aussi un texte collé, une page de votre site ou un fichier (PDF, Word, Excel…).', 'validated', 'import', 'apps:smart-agent', 'fr');
