INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('d4fd70ad-8f7b-4d11-ad95-41f008a2b0bb', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent · Valider', '{"statement":"Valider: une fiche ne sert l''agent que si VOUS l''avez validée. Les fiches en brouillon (dont celles des packs, à personnaliser: remplacez les [crochets]) sont inactives tant qu''elles ne sont pas validées."}', 'Smart Agent · Valider
Valider: une fiche ne sert l''agent que si VOUS l''avez validée. Les fiches en brouillon (dont celles des packs, à personnaliser: remplacez les [crochets]) sont inactives tant qu''elles ne sont pas validées.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('d4fd70ad-8f7b-4d11-ad95-41f008a2b0bb', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent · Valider', 'Smart Agent · Valider
