INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('6b28a6e5-9ab2-472e-a5c7-63678e271da7', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent · Tester', '{"statement":"Tester: l''onglet Tester est votre bac à sable — chaque réponse cite ses fiches sources, et le haut-parleur lit les réponses avec la voix neuronale Siwis. Les « Tests étalons » vérifient en un clic que l''agent répond là où il doit, et se tait là où il faut."}', 'Smart Agent · Tester
Tester: l''onglet Tester est votre bac à sable — chaque réponse cite ses fiches sources, et le haut-parleur lit les réponses avec la voix neuronale Siwis. Les « Tests étalons » vérifient en un clic que l''agent répond là où il doit, et se tait là où il faut.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('6b28a6e5-9ab2-472e-a5c7-63678e271da7', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent · Tester', 'Smart Agent · Tester
