INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('9d2907a6-eba1-48a7-bb1f-0ff37beeb164', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent · Combler les trous', '{"statement":"Combler les trous: quand l''agent sèche (chez vous ou face à un visiteur), la question atterrit dans l''onglet Trous, les reformulations d''une même question se cumulent. « Démarrer l''interview » les comble une par une, les plus demandées d''abord."}', 'Smart Agent · Combler les trous
Combler les trous: quand l''agent sèche (chez vous ou face à un visiteur), la question atterrit dans l''onglet Trous, les reformulations d''une même question se cumulent. « Démarrer l''interview » les comble une par une, les plus demandées d''abord.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('9d2907a6-eba1-48a7-bb1f-0ff37beeb164', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent · Combler les trous', 'Smart Agent · Combler les trous
Combler les trous: quand l''agent sèche (chez vous ou face à un visiteur), la question atterrit dans l''onglet Trous, les reformulations d''une même question se cumulent. « Démarrer l''interview » les comble une par une, les plus demandées d''abord.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('598338cf-42ca-484a-86e7-7aa7d147985e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent · Publier', '{"statement":"Publier: Réglages → « Publier cet agent » → lien public + QR code à imprimer. Vos visiteurs lui parlent sans compte; vous suivez le nombre de questions, le plafond par jour et l''expiration du lien."}', 'Smart Agent · Publier
Publier: Réglages → « Publier cet agent » → lien public + QR code à imprimer. Vos visiteurs lui parlent sans compte; vous suivez le nombre de questions, le plafond par jour et l''expiration du lien.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('598338cf-42ca-484a-86e7-7aa7d147985e', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent · Publier', 'Smart Agent · Publier
Publier: Réglages → « Publier cet agent » → lien public + QR code à imprimer. Vos visiteurs lui parlent sans compte; vous suivez le nombre de questions, le plafond par jour et l''expiration du lien.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('19bc455e-93ef-4d59-8be9-192289d58647', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'L''agent peut-il inventer une réponse ?', '{"question":"L''agent peut-il inventer une réponse ?","answer":"Non, c''est le principe fondateur: il ne répond que depuis vos fiches validées, en les citant (dans le bac à sable). Hors de son savoir, il le dit avec ses mots — sans rien inventer — et la question rejoint ses Trous pour que vous puissiez la combler."}', 'L''agent peut-il inventer une réponse ?
L''agent peut-il inventer une réponse ?
Non, c''est le principe fondateur: il ne répond que depuis vos fiches validées, en les citant (dans le bac à sable). Hors de son savoir, il le dit avec ses mots — sans rien inventer — et la question rejoint ses Trous pour que vous puissiez la combler.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('19bc455e-93ef-4d59-8be9-192289d58647', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'L''agent peut-il inventer une réponse ?', 'L''agent peut-il inventer une réponse ?
L''agent peut-il inventer une réponse ?
Non, c''est le principe fondateur: il ne répond que depuis vos fiches validées, en les citant (dans le bac à sable). Hors de son savoir, il le dit avec ses mots — sans rien inventer — et la question rejoint ses Trous pour que vous puissiez la combler.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('411d9a5b-b904-4832-b023-1cd9be1de95e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Qu''est-ce qui consomme mes crédits IA ?', '{"question":"Qu''est-ce qui consomme mes crédits IA ?","answer":"Une question posée à l''agent (par vous ou un visiteur public) et une extraction de fiches (coller un texte, lire une page web ou un fichier, structurer une réponse d''interview): 1 crédit chacune. Quand l''agent ne sait pas répondre sans génération, le crédit est rendu. La lecture vocale, la dictée et le correcteur de trous sont gratuits."}', 'Qu''est-ce qui consomme mes crédits IA ?
Qu''est-ce qui consomme mes crédits IA ?
Une question posée à l''agent (par vous ou un visiteur public) et une extraction de fiches (coller un texte, lire une page web ou un fichier, structurer une réponse d''interview): 1 crédit chacune. Quand l''agent ne sait pas répondre sans génération, le crédit est rendu. La lecture vocale, la dictée et le correcteur de trous sont gratuits.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('411d9a5b-b904-4832-b023-1cd9be1de95e', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Qu''est-ce qui consomme mes crédits IA ?', 'Qu''est-ce qui consomme mes crédits IA ?
Qu''est-ce qui consomme mes crédits IA ?
Une question posée à l''agent (par vous ou un visiteur public) et une extraction de fiches (coller un texte, lire une page web ou un fichier, structurer une réponse d''interview): 1 crédit chacune. Quand l''agent ne sait pas répondre sans génération, le crédit est rendu. La lecture vocale, la dictée et le correcteur de trous sont gratuits.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2ca09690-5b4a-4c4d-ba6b-ae1d5da21362', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Que voient mes visiteurs sur la page publique ?', '{"question":"Que voient mes visiteurs sur la page publique ?","answer":"Le nom de l''agent, son métier, son message d''accueil et ses réponses — jamais vos fiches, vos sources ni votre coffre. Leurs questions ne sont pas rattachées à leur identité et sont effacées après 90 jours."}', 'Que voient mes visiteurs sur la page publique ?
Que voient mes visiteurs sur la page publique ?
Le nom de l''agent, son métier, son message d''accueil et ses réponses — jamais vos fiches, vos sources ni votre coffre. Leurs questions ne sont pas rattachées à leur identité et sont effacées après 90 jours.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('2ca09690-5b4a-4c4d-ba6b-ae1d5da21362', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Que voient mes visiteurs sur la page publique ?', 'Que voient mes visiteurs sur la page publique ?
Que voient mes visiteurs sur la page publique ?
Le nom de l''agent, son métier, son message d''accueil et ses réponses — jamais vos fiches, vos sources ni votre coffre. Leurs questions ne sont pas rattachées à leur identité et sont effacées après 90 jours.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('488c9b57-f07e-4719-b4e2-65d69c0f8cb9', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Un visiteur peut-il épuiser mes crédits ?', '{"question":"Un visiteur peut-il épuiser mes crédits ?","answer":"Des garde-fous limitent chaque appareil (50 questions/jour) et chaque lien (plafond quotidien réglable dans Réglages → Publier, 500 par défaut). Vous pouvez aussi fixer une date d''expiration ou dépublier à tout moment — le lien et le QR cessent immédiatement de fonctionner."}', 'Un visiteur peut-il épuiser mes crédits ?
Un visiteur peut-il épuiser mes crédits ?
Des garde-fous limitent chaque appareil (50 questions/jour) et chaque lien (plafond quotidien réglable dans Réglages → Publier, 500 par défaut). Vous pouvez aussi fixer une date d''expiration ou dépublier à tout moment — le lien et le QR cessent immédiatement de fonctionner.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('488c9b57-f07e-4719-b4e2-65d69c0f8cb9', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Un visiteur peut-il épuiser mes crédits ?', 'Un visiteur peut-il épuiser mes crédits ?
Un visiteur peut-il épuiser mes crédits ?
Des garde-fous limitent chaque appareil (50 questions/jour) et chaque lien (plafond quotidien réglable dans Réglages → Publier, 500 par défaut). Vous pouvez aussi fixer une date d''expiration ou dépublier à tout moment — le lien et le QR cessent immédiatement de fonctionner.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('4dfb7b76-8b17-4136-be8e-26efb8f8cb18', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'À quoi servent le coffre partagé et les dossiers ?', '{"question":"À quoi servent le coffre partagé et les dossiers ?","answer":"Un dossier regroupe des agents (par établissement, par équipe…). Son coffre partagé contient le savoir commun à tous ses agents (horaires, règles maison): chaque agent lit son coffre privé ET le coffre partagé de son dossier."}', 'À quoi servent le coffre partagé et les dossiers ?
À quoi servent le coffre partagé et les dossiers ?
Un dossier regroupe des agents (par établissement, par équipe…). Son coffre partagé contient le savoir commun à tous ses agents (horaires, règles maison): chaque agent lit son coffre privé ET le coffre partagé de son dossier.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('4dfb7b76-8b17-4136-be8e-26efb8f8cb18', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'À quoi servent le coffre partagé et les dossiers ?', 'À quoi servent le coffre partagé et les dossiers ?
À quoi servent le coffre partagé et les dossiers ?
Un dossier regroupe des agents (par établissement, par équipe…). Son coffre partagé contient le savoir commun à tous ses agents (horaires, règles maison): chaque agent lit son coffre privé ET le coffre partagé de son dossier.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('87acf6a5-6a76-49ad-bfb2-8a27a51341bb', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'La voix et la dictée sont-elles payantes ?', '{"question":"La voix et la dictée sont-elles payantes ?","answer":"Non. La dictée utilise la reconnaissance vocale de votre navigateur, et la lecture utilise Siwis, une voix neuronale française hébergée par Keystone, exécutée dans votre navigateur (premier chargement d''environ 60 Mo, puis en cache). Aucun coût IA récurrent."}', 'La voix et la dictée sont-elles payantes ?
La voix et la dictée sont-elles payantes ?
Non. La dictée utilise la reconnaissance vocale de votre navigateur, et la lecture utilise Siwis, une voix neuronale française hébergée par Keystone, exécutée dans votre navigateur (premier chargement d''environ 60 Mo, puis en cache). Aucun coût IA récurrent.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('87acf6a5-6a76-49ad-bfb2-8a27a51341bb', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'La voix et la dictée sont-elles payantes ?', 'La voix et la dictée sont-elles payantes ?
La voix et la dictée sont-elles payantes ?
Non. La dictée utilise la reconnaissance vocale de votre navigateur, et la lecture utilise Siwis, une voix neuronale française hébergée par Keystone, exécutée dans votre navigateur (premier chargement d''environ 60 Mo, puis en cache). Aucun coût IA récurrent.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('047a3914-11d2-4082-b0c9-4286f37f1c51', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent — Pourquoi une IA invente', '{"statement":"Un modèle de langage ne consulte pas une base de vérité: il prédit la suite de mots la plus probable. Sans cadre, il puise dans des connaissances générales, périmées ou inadaptées à votre activité. Le problème n''est pas l''IA en soi, c''est de la laisser répondre sans source."}', 'Smart Agent — Pourquoi une IA invente
Un modèle de langage ne consulte pas une base de vérité: il prédit la suite de mots la plus probable. Sans cadre, il puise dans des connaissances générales, périmées ou inadaptées à votre activité. Le problème n''est pas l''IA en soi, c''est de la laisser répondre sans source.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('047a3914-11d2-4082-b0c9-4286f37f1c51', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent — Pourquoi une IA invente', 'Smart Agent — Pourquoi une IA invente
Un modèle de langage ne consulte pas une base de vérité: il prédit la suite de mots la plus probable. Sans cadre, il puise dans des connaissances générales, périmées ou inadaptées à votre activité. Le problème n''est pas l''IA en soi, c''est de la laisser répondre sans source.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('cfe1e803-35ea-4c7f-95a0-3de1a40a6e7b', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent — Ce qui change avec un agent ancré', '{"statement":"Un savoir validé par vous: l''agent ne répond qu''à partir d''un coffre de connaissances que vous avez écrit et approuvé (horaires, tarifs, conditions, FAQ). Le droit de dire « je ne sais pas »: face à une question hors périmètre, un bon agent renvoie vers un humain plutôt que d''improviser. Une mise à jour instantanée: un tarif change, vous corrigez le coffre, l''agent répond juste dès la seconde suivante."}', 'Smart Agent — Ce qui change avec un agent ancré
Un savoir validé par vous: l''agent ne répond qu''à partir d''un coffre de connaissances que vous avez écrit et approuvé (horaires, tarifs, conditions, FAQ). Le droit de dire « je ne sais pas »: face à une question hors périmètre, un bon agent renvoie vers un humain plutôt que d''improviser. Une mise à jour instantanée: un tarif change, vous corrigez le coffre, l''agent répond juste dès la seconde suivante.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('cfe1e803-35ea-4c7f-95a0-3de1a40a6e7b', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent — Ce qui change avec un agent ancré', 'Smart Agent — Ce qui change avec un agent ancré
Un savoir validé par vous: l''agent ne répond qu''à partir d''un coffre de connaissances que vous avez écrit et approuvé (horaires, tarifs, conditions, FAQ). Le droit de dire « je ne sais pas »: face à une question hors périmètre, un bon agent renvoie vers un humain plutôt que d''improviser. Une mise à jour instantanée: un tarif change, vous corrigez le coffre, l''agent répond juste dès la seconde suivante.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2148f8c5-25f2-4861-bd76-b5b4048341fa', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Smart Agent — Ce que ça apporte concrètement', '{"statement":"Vos clients obtiennent une réponse fiable à toute heure, sans que vous ayez à surveiller chaque échange. Vous gardez la main sur ce qui est dit en votre nom, et vous repérez les questions sans réponse — celles qui révèlent un trou dans votre information. Smart Agent repose exactement sur ce principe: un agent ancré sur votre savoir-faire, qui cite ses sources et préfère se taire plutôt qu''inventer."}', 'Smart Agent — Ce que ça apporte concrètement
Vos clients obtiennent une réponse fiable à toute heure, sans que vous ayez à surveiller chaque échange. Vous gardez la main sur ce qui est dit en votre nom, et vous repérez les questions sans réponse — celles qui révèlent un trou dans votre information. Smart Agent repose exactement sur ce principe: un agent ancré sur votre savoir-faire, qui cite ses sources et préfère se taire plutôt qu''inventer.', 'validated', 'import', 'apps:smart-agent', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('2148f8c5-25f2-4861-bd76-b5b4048341fa', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Smart Agent — Ce que ça apporte concrètement', 'Smart Agent — Ce que ça apporte concrètement
Vos clients obtiennent une réponse fiable à toute heure, sans que vous ayez à surveiller chaque échange. Vous gardez la main sur ce qui est dit en votre nom, et vous repérez les questions sans réponse — celles qui révèlent un trou dans votre information. Smart Agent repose exactement sur ce principe: un agent ancré sur votre savoir-faire, qui cite ses sources et préfère se taire plutôt qu''inventer.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('d78dfce9-b6ca-415c-b0ad-b1e5297fc66e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'definition', 'Smart Dynamic QR, en une phrase', '{"term":"Smart Dynamic QR","definition":"Smart Dynamic QR crée des QR codes souverains avec tracking RGPD natif. Statiques ou dynamiques (modifiables après impression), brandés à votre charte, sans dépendance Google."}', 'Smart Dynamic QR, en une phrase
Smart Dynamic QR
