INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('d02096ed-6a61-47c4-bf3a-4935a666d1fc', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Quels réseaux sont gérés aujourd''hui ?', '{"question":"Quels réseaux sont gérés aujourd''hui ?","answer":"Facebook (pages), Instagram (comptes professionnels liés à une page), Threads et Telegram (canaux et groupes). D''autres viendront selon la demande — X a été volontairement écarté (accès payant imposé par la plateforme, contraire à notre formule tout compris)."}', 'Quels réseaux sont gérés aujourd''hui ?
Quels réseaux sont gérés aujourd''hui ?
Facebook (pages), Instagram (comptes professionnels liés à une page), Threads et Telegram (canaux et groupes). D''autres viendront selon la demande — X a été volontairement écarté (accès payant imposé par la plateforme, contraire à notre formule tout compris).', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('d02096ed-6a61-47c4-bf3a-4935a666d1fc', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Quels réseaux sont gérés aujourd''hui ?', 'Quels réseaux sont gérés aujourd''hui ?
Quels réseaux sont gérés aujourd''hui ?
Facebook (pages), Instagram (comptes professionnels liés à une page), Threads et Telegram (canaux et groupes). D''autres viendront selon la demande — X a été volontairement écarté (accès payant imposé par la plateforme, contraire à notre formule tout compris).');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('4ba37322-efe8-4add-9ea2-fd3e4c3b0c76', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Keystone connaît-il mes mots de passe ?', '{"question":"Keystone connaît-il mes mots de passe ?","answer":"Jamais. Facebook, Instagram et Threads utilisent leur connexion officielle (vous autorisez Keystone depuis VOTRE session, et pouvez révoquer à tout moment depuis le réseau). Telegram utilise un jeton de bot que vous créez vous-même."}', 'Keystone connaît-il mes mots de passe ?
