INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('ca52d981-0dd9-487a-8487-75504eb3147a', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Que se passe-t-il si un envoi échoue ?', '{"question":"Que se passe-t-il si un envoi échoue ?","answer":"L''envoi se retente automatiquement (jusqu''à 4 tentatives espacées de 5, 15 puis 60 minutes), et UNIQUEMENT sur les réseaux qui ont échoué — jamais de double publication sur ceux qui ont réussi. Au-delà, le post passe en erreur avec un bouton « Renvoyer »."}', 'Que se passe-t-il si un envoi échoue ?
Que se passe-t-il si un envoi échoue ?
L''envoi se retente automatiquement (jusqu''à 4 tentatives espacées de 5, 15 puis 60 minutes), et UNIQUEMENT sur les réseaux qui ont échoué — jamais de double publication sur ceux qui ont réussi. Au-delà, le post passe en erreur avec un bouton « Renvoyer ».', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('ca52d981-0dd9-487a-8487-75504eb3147a', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Que se passe-t-il si un envoi échoue ?', 'Que se passe-t-il si un envoi échoue ?
Que se passe-t-il si un envoi échoue ?
L''envoi se retente automatiquement (jusqu''à 4 tentatives espacées de 5, 15 puis 60 minutes), et UNIQUEMENT sur les réseaux qui ont échoué — jamais de double publication sur ceux qui ont réussi. Au-delà, le post passe en erreur avec un bouton « Renvoyer ».');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2827a38c-f918-4fe9-b45c-6363d425ec38', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Un post programmé part-il si je ferme mon navigateur ?', '{"question":"Un post programmé part-il si je ferme mon navigateur ?","answer":"Oui. La programmation vit côté serveur: le post part à l''heure dite (à 5 minutes près), dashboard ouvert ou non, ordinateur éteint ou non."}', 'Un post programmé part-il si je ferme mon navigateur ?
Un post programmé part-il si je ferme mon navigateur ?
