INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('c7271126-a23e-4718-ae03-43749593e1bb', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Puis-je voir les performances de mes posts ?', '{"question":"Puis-je voir les performances de mes posts ?","answer":"Oui, à la demande: les statistiques (vues, réactions) sont relevées depuis les réseaux qui les fournissent gratuitement — Facebook, Instagram et Threads. Telegram ne fournit pas de statistiques aux bots, ce réseau reste donc sans chiffres."}', 'Puis-je voir les performances de mes posts ?
Puis-je voir les performances de mes posts ?
Oui, à la demande: les statistiques (vues, réactions) sont relevées depuis les réseaux qui les fournissent gratuitement — Facebook, Instagram et Threads. Telegram ne fournit pas de statistiques aux bots, ce réseau reste donc sans chiffres.', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('c7271126-a23e-4718-ae03-43749593e1bb', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Puis-je voir les performances de mes posts ?', 'Puis-je voir les performances de mes posts ?
Puis-je voir les performances de mes posts ?
Oui, à la demande: les statistiques (vues, réactions) sont relevées depuis les réseaux qui les fournissent gratuitement — Facebook, Instagram et Threads. Telegram ne fournit pas de statistiques aux bots, ce réseau reste donc sans chiffres.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('55a406c8-6792-4faf-913f-3a61525224a8', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Pourquoi mon Instagram n''apparaît-il pas après la connexion Facebook ?', '{"question":"Pourquoi mon Instagram n''apparaît-il pas après la connexion Facebook ?","answer":"Instagram exige un compte professionnel LIÉ à une page Facebook, et c''est cette page qui doit être choisie pendant la connexion. Si votre Instagram est lié à une autre page (ou à aucune), reliez-le d''abord dans les paramètres Meta, puis reconnectez."}', 'Pourquoi mon Instagram n''apparaît-il pas après la connexion Facebook ?
Pourquoi mon Instagram n''apparaît-il pas après la connexion Facebook ?
Instagram exige un compte professionnel LIÉ à une page Facebook, et c''est cette page qui doit être choisie pendant la connexion. Si votre Instagram est lié à une autre page (ou à aucune), reliez-le d''abord dans les paramètres Meta, puis reconnectez.', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('55a406c8-6792-4faf-913f-3a61525224a8', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Pourquoi mon Instagram n''apparaît-il pas après la connexion Facebook ?', 'Pourquoi mon Instagram n''apparaît-il pas après la connexion Facebook ?
Pourquoi mon Instagram n''apparaît-il pas après la connexion Facebook ?
Instagram exige un compte professionnel LIÉ à une page Facebook, et c''est cette page qui doit être choisie pendant la connexion. Si votre Instagram est lié à une autre page (ou à aucune), reliez-le d''abord dans les paramètres Meta, puis reconnectez.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('2597f691-1e25-4567-880f-8168203ef452', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'qa', 'Plusieurs images dans un même post ?', '{"question":"Plusieurs images dans un même post ?","answer":"Pas encore: un post = un texte + une image au maximum, sur tous les réseaux. Le carrousel est à l''étude."}', 'Plusieurs images dans un même post ?
