INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('24311c19-1e16-422b-8543-01c4c75a193d', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Social Manager — Régularité plutôt que perfection', '{"statement":"Un message correct publié chaque semaine vaut mieux qu''un message brillant tous les six mois. Les algorithmes comme votre audience récompensent la présence constante. Mieux vaut viser un rythme tenable et s''y tenir que viser l''excellence et décrocher au bout d''un mois."}', 'Social Manager — Régularité plutôt que perfection
Un message correct publié chaque semaine vaut mieux qu''un message brillant tous les six mois. Les algorithmes comme votre audience récompensent la présence constante. Mieux vaut viser un rythme tenable et s''y tenir que viser l''excellence et décrocher au bout d''un mois.', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('24311c19-1e16-422b-8543-01c4c75a193d', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Social Manager — Régularité plutôt que perfection', 'Social Manager — Régularité plutôt que perfection
Un message correct publié chaque semaine vaut mieux qu''un message brillant tous les six mois. Les algorithmes comme votre audience récompensent la présence constante. Mieux vaut viser un rythme tenable et s''y tenir que viser l''excellence et décrocher au bout d''un mois.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('b526ea2f-4f5d-4b1a-a76d-275ace61175e', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Social Manager — Écrire une fois, publier partout', '{"statement":"Vous n''avez pas à réécrire votre message pour chaque réseau. Partez d''une idée, adaptez-la une fois au format de chaque plateforme, et diffusez-la sur tous vos comptes d''un même geste. Le gain de temps est immédiat, et votre discours reste cohérent partout."}', 'Social Manager — Écrire une fois, publier partout
Vous n''avez pas à réécrire votre message pour chaque réseau. Partez d''une idée, adaptez-la une fois au format de chaque plateforme, et diffusez-la sur tous vos comptes d''un même geste. Le gain de temps est immédiat, et votre discours reste cohérent partout.', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('b526ea2f-4f5d-4b1a-a76d-275ace61175e', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Social Manager — Écrire une fois, publier partout', 'Social Manager — Écrire une fois, publier partout
Vous n''avez pas à réécrire votre message pour chaque réseau. Partez d''une idée, adaptez-la une fois au format de chaque plateforme, et diffusez-la sur tous vos comptes d''un même geste. Le gain de temps est immédiat, et votre discours reste cohérent partout.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('4a9b9815-970d-4b99-8f46-d4e92da66d00', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Social Manager — Programmer et batcher', '{"statement":"Batcher: réservez une heure pour préparer plusieurs publications d''un coup, plutôt que d''y penser chaque jour. La charge mentale s''effondre. Programmer: planifiez ces publications à l''avance, aux bons horaires, et oubliez-les. Vos réseaux vivent même quand vous travaillez sur autre chose. Tenir un cap: deux ou trois publications par semaine, régulières, suffisent à exister."}', 'Social Manager — Programmer et batcher
Batcher: réservez une heure pour préparer plusieurs publications d''un coup, plutôt que d''y penser chaque jour. La charge mentale s''effondre. Programmer: planifiez ces publications à l''avance, aux bons horaires, et oubliez-les. Vos réseaux vivent même quand vous travaillez sur autre chose. Tenir un cap: deux ou trois publications par semaine, régulières, suffisent à exister.', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('4a9b9815-970d-4b99-8f46-d4e92da66d00', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Social Manager — Programmer et batcher', 'Social Manager — Programmer et batcher
Batcher: réservez une heure pour préparer plusieurs publications d''un coup, plutôt que d''y penser chaque jour. La charge mentale s''effondre. Programmer: planifiez ces publications à l''avance, aux bons horaires, et oubliez-les. Vos réseaux vivent même quand vous travaillez sur autre chose. Tenir un cap: deux ou trois publications par semaine, régulières, suffisent à exister.');
INSERT INTO kortex_units (id, tenant_id, agent_id, vault_id, type, title, body, body_text, status, source_kind, source_ref, lang) VALUES ('efa09834-88db-450f-8515-2d12a49b6f4b', 'default', '4c2691e8-085b-409b-af80-f8ca441c96db', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'fact', 'Social Manager — Réutiliser ce qui marche', '{"statement":"Vous n''avez pas besoin d''une idée neuve à chaque fois. Une question fréquente de vos clients, une coulisse de votre métier, un avis reçu, une réponse à une objection courante: ce sont des publications. Gardez sous la main une réserve de ces formats simples et puisez dedans quand l''inspiration manque. L''objectif n''est pas de devenir community manager, mais de rester visible sans y sacrifier votre métier. Social Manager réunit ces réflexes: un message écrit une fois, adapté et publié sur vos réseaux, programmé à l''avance."}', 'Social Manager — Réutiliser ce qui marche
Vous n''avez pas besoin d''une idée neuve à chaque fois. Une question fréquente de vos clients, une coulisse de votre métier, un avis reçu, une réponse à une objection courante: ce sont des publications. Gardez sous la main une réserve de ces formats simples et puisez dedans quand l''inspiration manque. L''objectif n''est pas de devenir community manager, mais de rester visible sans y sacrifier votre métier. Social Manager réunit ces réflexes: un message écrit une fois, adapté et publié sur vos réseaux, programmé à l''avance.', 'validated', 'import', 'apps:social-manager', 'fr');
INSERT INTO kortex_units_fts_v2 (unit_id, tenant_id, vault_id, title, body_text) VALUES ('efa09834-88db-450f-8515-2d12a49b6f4b', 'default', 'e1dccc3c-7656-4957-bd07-7421857b696c', 'Social Manager — Réutiliser ce qui marche', 'Social Manager — Réutiliser ce qui marche
Vous n''avez pas besoin d''une idée neuve à chaque fois. Une question fréquente de vos clients, une coulisse de votre métier, un avis reçu, une réponse à une objection courante: ce sont des publications. Gardez sous la main une réserve de ces formats simples et puisez dedans quand l''inspiration manque. L''objectif n''est pas de devenir community manager, mais de rester visible sans y sacrifier votre métier. Social Manager réunit ces réflexes: un message écrit une fois, adapté et publié sur vos réseaux, programmé à l''avance.');
